// Auto-generated from HISTORY_1884__1967.pdf — chronological club chronicle.
// Source: club archive.  Each entry's `body` is the newspaper excerpt for that date.

export type ChronicleEntry = {
  date: string;   // e.g. "17th MAY 1884"
  year: number;   // 1884-1967
  body: string;
};

export const CHRONICLE: ChronicleEntry[] = [
  { date: '17th MAY 1884', year: 1884, body: 'The first General Meeting of the Wallaroo Football Club was held on Wednesday evening at the Ship Inn for the purpose of receiving the balance sheet and appointing officers for the coming year. The balance sheet was read by the Secretary Mr G. Middleton and showed the club to be in a good financial position. Officers elected:- Patron – Mr E. Warmington, President – Mr J. Malcolm, Vice Presidents – Messrs Maughan, Cropley and Dr Gosse, Captain – Mr R. Walsh, Vice aptain – Mr A. Tomlin, Secretary – Mr G. Middleton, Treasurer – Mr J. Lethely and the names of Messrs Levido, Griffiths and Keeling added to the committee. In answer to a report from the Standard Football Club, it was decided that the clubs should amalgamate and the members of the Standard should be allowed to enter free on condition that they deliver all things belonging to the club. It was suggested that the Peninsula clubs form an Assocation but this did not meet with approval of the meeting. Opening game to be played today, ball to be kicked off by Mr Warmington.' },
  { date: '1st APRIL 1885', year: 1885, body: 'A. G. M Wallaroo Football Club, held at Ship Inn on Thursday evening, with a large crowd in attendance. Mr Keating was voted to the chair. Officers elected:- Patron – Mr E. Warmington Esq J. P, President – Mr Bews Esq M. P, Vice Presidents – Messrs L. L Furner, M. M. Maughan, S. Cropley, J. Gosse, J. Manson, A. W. Burton, W. Phillips(Mayor), S. Bowman, E. J. Birbeck, Jas Hay, T. C. Cloudand D. Taylor, Captain – A. E. Tomlin, Vice Captain – E. Bowman, Secretary/Treasurer Mr G. J. Middleton, the following with the other offices to form the committee J. Richards, R. Snook, J. Thomas, R. Walsh. The opening game to be played on Saturday 11th April.' },
  { date: '1st AUGUST 1885', year: 1885, body: 'Football: Moonlight football match was played between a senior t eam which fielded a very week team and Wallaroo junior team of twenty five players. It was played on the grounds near the Fuse Factory. The final score was Wallaroo Seniors 1 goal 3 behinds to Juniors 0 goals 8 behinds.' },
  { date: '27th MARCH 1886', year: 1886, body: 'A. G. M. Wallaroo Football Club held Thursday night 25 th March 1886 at the Ship Inn. Officers elected were:- President – Mr E. Warmington, Vice Presidents – Messrs Hay, Cloud, Bowman and Cropley, Captain – A. E. Tomlin, Vice Captain – T. Lambert, Secretary – G. J. Middleton, Committee – Captain, Vice, Secretary and Messrs J. Thomas, W. Middleton and W. Thomas. It was decided to ask the opinion of the Peninsula clubs as to the desirability of forming a Football Association.' },
  { date: '7th MARCH 1888', year: 1888, body: 'Meeting held Tuesday evening 6th March: The following were elected: President – Mr E. Warmington, Vice Presidents – Messrs J. Malcolm(Mayor), G. J. Middleton, W. J. Ponder, Jas Hay, S. Bowman, S. Cropley and G. Chatfield, Captain – Mr J. Herbert, Vice Captain – Mr T. Kiely, Secretary/Treasurer – Mr G. J. Middleton, Assistant Secretary – Mr L. Walters. A letter was received from the Moonta Club about forming a Football Association, it was considered advisable to form an Association and Messrs Donnell and Middleton were elected as Delegates.' },
  { date: '1st MAY 1889', year: 1889, body: 'Wallaroo defeats East Moonta at East Moonta, final scores Wallaroo 5 goals 11 behinds to East Moonta 0 goals 1 behind.' },
  { date: '25th MARCH 1893', year: 1893, body: 'Yorke Peninsula Football Association consisted of Wallaroo, Kadina, Wallaroo Mines, Moonta Turks, East Moonta, Moonta and Cross Roads.' },
  { date: '29th JULY 1893', year: 1893, body: 'Wallaroo Team: G. Gepp(Captain), Kempster, McKee, O’Loughlin, Power, Davies, Warmington, Hopkins(2), Middleton, Dalby, J. Thomas, W. Thomas, D. Thomas, Kessell, Levido, Clements, John, Wincher, Brown.' },
  { date: '2nd MAY 1894', year: 1894, body: 'Wallaroo beat East Moonta: Final scores Wallaroo 5 goals 20 behi nds to East Moonta 3 goals 4 behinds Umpire Mr C. Bird of Kadina.' },
  { date: '12th MAY 1894', year: 1894, body: 'WallarooTeam: Gepp(Captain), Kempster, Hopkins(3), Thomas(2), Davies, Willis, Levido, Middleton, Dalby, Davies, Hunter, G. Bird, Clements, Power, Warmington and Gill(2). Emergencies B. Bird, R. Price.' },
  { date: '2nd APRIL 1900', year: 1900, body: 'Delegates to Y. P. Football Associaton were Messrs W. Shea and A. O’Brien from Wallaroo Club.' },
  { date: '18th MARCH 1905', year: 1905, body: 'The Annual meeting of the Y. P. Football Association was held at the Globe Hotel(Moonta)on Wednesday night 15th March last, Mr W. H. Harvey presiding. The whole of the association were represented, (Moonta, Moonta Mines, Turks, Wallaroo Mines, Wallaroo & East Moonta). After the Secretary(Mr R. J. Hughes)presented his report & balance sheet which showed an excellent position financially, the Officers were elected as follows : Patron Dr T. K. Fulton :Presidents Dr H. A. Powell(Kadina), Mr J. F Herbert(Wallaroo), Mr W. H. Harvey(Moonta) :Vice Presidents Mr W. Chappell(Moonta), Mr F. Taylor(Kadina), Mr J. Gross(Wallaroo) :Secretary/Treasurer Mr R. J. Hughes : Auditors Messrs T. H. Cock & A. E. Raggett. Messrs T. Birtles & W. J. D. Phillips were appointed a sub committee to revise rules and report at the next meeting. The meeting adjourned until Wednesday April 12 th, at Kadina. Moonta Mines was known as the Turks.' },
  { date: '18th OCTOBER 1905', year: 1905, body: 'Y. P. Association: Wallaroo wins the Premiership at the Moonta oval Satuday last 14 th October. Final scores Wallaroo 10 – 3(63) Wallaroo Mines 5 – 1(31) Best for the winners Thomas, Jones, Williams, Walsh, Buck, Surfield, Kissell & Bishop.' },
  { date: '28th APRIL 1906', year: 1906, body: 'Y. P. Football Association: Held at Moonta on Wednesday 25th April. A letter was received from Mr J. Snell accepting the position of Vice President. Applications for the position of Field umpire were received from Messrs W. H. H ollands & J. T. Sellars(Wallaroo), Jas Richards(Cross Roads), S. Martin(Moonta), S. Carter & C. Penhall(Wallaroo Mines), W. Wallace, J. Cock, R. C. Trebilcock, F. Prout(Moonta Mines). Messrs Hollands, Richards, Martin, Carter & Wallace were appointed.' },
  { date: '6th JUNE 1906', year: 1906, body: 'Y. P. Football Association: A meeting of the Appeals Committee of the Y. P. Association was held on Monday evening 4th June 1906 to consider the protest lodged by the Wallaroo club against the Moonta Mines Turks for playing Meadows O’Leary & Maddaford on May 19th on the grounds that they had not resided in the district two weeks prior to the match. After hearing three witnesses, it was resolved by four votes to one that the match be awarded to Wallaroo club.' },
  { date: '18th SEPTEMBER 1907', year: 1907, body: 'Wallaroo Premiers for 1907: This season the seasiders have won the two minor premierships a feat never before has been achieved by any of the associated clubs. They have had a wonderful perfomance of only two losses, both against Moonta Turks.' },
  { date: '18th MARCH 1908', year: 1908, body: 'Wallaroo Football Club: The Annual meeting was held at the Bay View Hotel on Tuesday evening March 10th 1908. Mr R. Thomas presided over a good attendance. The Secretary Report and Balance Sheet which showed the club to be in a good financial position. They had r eceived the minor and major premierships scoring for the season 34 points out of a possible 38. Two players received first and second awards in the Copper Age trophy for the best all - round player on the Peninsula. Doug Walsh securing first honors with 146 votes and E. Jones second with70 votes. T. Thomas(Captain of the club)was awarded the Richmond Cap for the best man in the team. The following were elected for the ensuing year: Patron Mr J. Richmond : President Dr Wilson : Vice Presidents to be left in the han ds of the secretary. Captain Mr T. Thomas : Vice Captain Mr D. Walsh :Secretary Mr W Bryden : Treasurer Mr T. Kelly : Selection Committee & Working Committee Messrs R. Thomas & W. Paull plus Captain, Vice Captain & Secretary : Delegates Messrs R. Thomas & S. Juniper : Board of Appeal Messrs R. Thomas(delegate) & W. Shea(deputy delegate) : Time Keepers Messrs R. Thomas & E. Strongman : Tainers Messrs G. Sandford, H. McLean & W. Paull : Goal Umpires Messrs H. R. Walsh, C. Elliott & J. Buck : Auditors Messrs P. O’Loughlin & H. R. Walsh. A vote of thanks was moved to the past officers for the valuable services renderd to the Club. Meeting closed.' },
  { date: '21st MARCH 1908', year: 1908, body: 'Y. P. Association Meeting: Among business dealt with were:- It was decided in accordance with the recommendation of the sub-committee, that this season the two leading teams in each half of the season play off for the minor premiership, and that if necessary the two winning teams play off at the end of the season for the major premiership.' },
  { date: '16th APRIL 1910', year: 1910, body: 'Y. P. Association Meeting held at Moonta at which Dr Clayton presided over on Monday 11 th April. Among the business applications were called for (position of field umpires) were received from J. Thomas(Wallaroo), C. J. Herbert(Cross Roads), H. Nancarrow(Moonta) and A. O’Connor(Wallaroo Mines), all of which were accepted. Fifteen applications for the position of boundary umpire were received and the folloeing were accepted F. Franciso, F. Hopkins(Wallaroo), H. Diver, L. J. Skinner(Wallaroo Mines), Whitbread, C. W. Pen hall (Kadina), H. Cornelius, A. E. Manuel, A. Hand, A. F. Lennell, T. P. Couch and N. Spry(Moonta).' },
  { date: '19th OCTOBER 1910', year: 1910, body: 'Football Presentation of various trophies won in connection with the Wallaroo Football Club for the season 1910, took place at the Rowing Club Ball held in the Waterside workers hall on Friday evening last. Dr Wilson patron of the club presented the trophies to the successful players, which is as follows: - Gold Medal, presented by Mr Dodge(Postmaster of Wallaroo)for the most unselfish player won by E. Barnes, Gold Medal , presented by Mr R. Thomas for the best place man, won by G. Payne, Gold Medal presented by Mrs Bond for the highest number of goals kicked, won by T. Buck, Gold Medal , presented by Dr Wilson for the most consistent player, won by H. Clayton. Watch presented by Mr Williams for the most brilliant player, won by H. Sellars.' },
  { date: '1st APRIL 1911', year: 1911, body: 'Yorke Peninsula Football Association meeting held at the Cornucopia Hotel Wallaroo, on Wed evening March 29th. In the absence of the President of Wallaroo(Mr J. F. Herbert)the Vice President (Dr C. E. Wilson) presided, and all the associated clubs were represented. An application was received from the Moonta Club for re-admission to the association, enclosing the necessary fees and presenting a list of some thirty three players who had promised their support. The Delegates of Moonta(Messrs W. Richards and A. Mosel)having stated their case, a motion was tabled to the effect that the Moonta Club be re-admitted without the usual entrance fee, a ballot resulted in favour of the motion by 6 votes to 2. The Moonta Delegates were then admitted to the meeting. Nominations of Delegates and members of the Appeal Committee was made as follows: Association - Wallaroo(S. Juniper, W. Bryden), Turks(R. Searle, A. L. Floyd), Kadina(R. Truscott, G. T. Herbert), Federal Rovers(W. Henderson, W. H. Davey), Moonta(W. Richards, A. Mosel). Appeal Committee- Wallaroo - N. Walters, (W. Bryden deputy), Turks – R. Searle, (A. L. Floyd deputy), Kadina – G. T. Herbert, (R. Truscott deputy), Federal Rovers – W. Henderson, (A. Spry deputy), Moonta – W. Richards, (V. G. Crutchett deputy). Goal Umpires were nominated and approved as follows, Wallaroo – W. Williams, E. Doyle, F. Edwards, Turks – F. Hobb, A. Curtis, R. Richards, Kadina – T. Elliott, J. Anderson, R. Gillolme, Federal Rovers – H. Crocker, T. Hattam, J. Tippett, Moonta – R. Abraham, W. Hosking, J. Angove. The election of Officers for the ensuing term as follows: Patron – Mr W. H. Harvey, Presidents – Mr J. F. Herbert(Wallaroo), Dr A. R Clayton(Moonta) and Mr W. F. Owen(Kadina). Vice Presidents Dr C. E. Wilson(Wallaroo), Mr R. Learmond(Moonta) and Mr M. J. Reed(Kadina). Secretary/Treasurer Mr R. J. Hughes, Auditors Messrs T. H. Cock and A. E. Raggett.' },
  { date: '16th MARCH 1912', year: 1912, body: 'Wallaroo Football Club Annual General Meeting held in the Wallaroo town hall chambers on Monday evening last Dr C. E. Wilson presided over a large attendance. The Secretary Mr W. Bryden reported that the club position on the premiership list last year was the lowest on record. The following were elected as officers for the coming season. Patron – Dr C. E. Wilson, President – Mr W. J. Dodge, Vice Presidents – Messrs S. G. Hockridge, J. Liddy, C. Goodfellow, J. Rees, J. Maddon, G. Chatfield, W. Coombe J. E. Hawke, J. C. Daymond and Mesdames Bryden and Trye, the election Captain and Vice Captains was left open, Practice Captain - Mr E. Barnes, Secretary - Mr W. Bryden, Treasurer - Mr T. J. Kelly, Club Delegates – Messrs R. G. Thomas and W. Bryden, Selection and General Committee – Captain, Vice, Secretary and Messrs W. J. Williams and T. Young. Auditors – Messrs P. Oloughlin and S. M. Watt. Trainers - Messrs W. Paull, G. Sandford, F. Hopkins, E. Peddar and W. H. McLean. Timekeepers – Messrs W. Shea and F. Edwards, Scorer – Mr F. Edwards, Goal Umpires – Messrs E. Doyle, W. J. Williams, G. Sandford and E. Appleton. Dr Wilson promised a trophy for the most improved Junior player. The club also intends donating a trophy to the player who attends practice most regularly and carries out the instructions of the coach.' },
  { date: '18th SEPTEMBER 1912', year: 1912, body: 'On Saturday afternoon at Moonta Recreation Ground the second minor premiershi p between Wallaroo and Kadina (premiers of the first half) was won by Wallaroo by two points. The three principal contributors to the success of Wallaroo team were H. Sellars, A. Clayton and F. Peddar.' },
  { date: '25th SEPTEMBER 1912', year: 1912, body: 'Yorke Peninsula Football Premiership. Kadina on top again, splendid final quarter by the red and blacks. The 1912 season was bought to a close when the Kadina(first minor premiers) defeated Wallaroo(second minor premiers) at the Moonta ground With eleven points to spare. A large crowd witnessed the match, Kadina in the final quarter 2 goals 2 behinds to Wallaroo’s 1 goal. The best for Wallaroo were A. Clayton supported by G. Payne, H. Sellars, R. Whenan, L. Davies and F. Peddar others played well.' },
  { date: '15th MARCH 1913', year: 1913, body: 'Annual Meeting of the Wallaroo Football Club:- Held at the Council Chambers, Town Hall building on Monday evening last. The Honrable Secretary Mr W. Bryden gave his report which stated that during last Seasonthe played fourteen ordinary matches and one play off. The points scored were 753 for and 535 against. The highest number of goals kicked was by J. Peddar who kicked 27 goals. Trophies won during the season were presented to the successful players by the Patron(Dr Wilson) and the Mayor(Mr J. F. Herbert M. P. ) at a benefit night given by Mr G. Hollands(Olympic Pictures). The main office bearers for the ensuing year as follows:- Patron – Dr C. E. Wilson, President – Mr W. J. Dodge, Vice Presidents – Mrs Trye, Messrs Liddy, Hockridge, Maddon, T. Young and others at Secretary’s discretion. Secretary – Mr W. Bryden, Treasurer – Mr T. Kelly, Delegates to the Y. P. Association – Messrs T. Young and F. W. Birbeck. Selection and General Committee – Captain, Vice Captain, Secretary, Messrs W. L. Williams and T. Young.' },
  { date: '26th MARCH 1913', year: 1913, body: 'Yorke Peninsula football season for 1913 starts on 12th April. Patron - Mr W. H. Harvey, Presidents – Dr A. R. C. Clayton(Moonta), Mr L. H. Shepley(Kadina) and Mr J. F. Herbert M. P. (Wallaroo), Vice Presidents – Messrs R. Learmond(Moonta), M. J. Reed(Kadina) and DrC. E. Wilson(Wallaroo), Sec retary/Treasurer – Mr R. J. Hughes, Auditors – Messrs T. H. Cock and A. E. Raggett.' },
  { date: '3rd SEPTEMBER 1913', year: 1913, body: 'Wallaroo Footballers trip to Cowell. They traveled across to Cowell by the ship S. S. Wandance. The host at Cowell was Mr W. Ogilvie, late of the Globe Hotel Wallaroo. The trip included a visit to the Ullabidnie Weir. On Sunday afternoon a match was played against a local team which Wallaroo won by five points' },
  { date: '15th OCTOBER 1913', year: 1913, body: 'Yorke Peninsula Football Premiership of second half: Wallaroo wins easily: A large crowd saw Wallaroo defeat Kadina at Moonta final scores Wallaroo 9 goals 8 behinds(62) to Kadina 4 goals 9 behinds(33). The four Chief contributors for Wallaroo were H. Murch, H. Brown, L. Davies and L. C. Clayton.' },
  { date: '22nd OCTOBER 1913', year: 1913, body: 'Presentation to Mr Thomas Thomas: On Monday evening at the Cornucopia Hotel in the presence of all members of the Wallaroo Football Club and supporters, a presentation of a purse of sovereigns was made to Mr Thomas(beter known as “Masher”) Thomas. The Mayor Mr J. F. Herbert, presided, he explained that the gathering was to show in some practical manner the appreciation of the Club and public generally of the great servicesMr Thomas has rendered to the club as Coach in training the team for Premiership matches. The sum of 25 pounds was raised in a very short time, various toasts were proposed and drank to, plus various speakers paid tribute to Mr Thomas. Mr Thomas in his response said he very thankful to them for thei kindness, he had many surprises in his life but tonight had capped the list. Finally he said he would never forget their kindness.' },
  { date: '22nd OCTOBER 1913', year: 1913, body: 'Wallaroo who won the second Premiership played Kadina winners of the first Premiership(played at Moonta) which was won by Wallaroo by one point. Scores being Wallaroo 8 goals 7 behinds(55points) to Kadina 8 goals 6 behinds(54points). Wallaroo it was not easy to pick best players as all played well, but C. Murch and L. Davies were the two best. E. L. Renfrey was pick of the Kadina team.' },
  { date: '26th NOVEMBER 1913', year: 1913, body: 'Complimentary Dinner at the Wallaroo Town Hall. Club attended a complimentary dinner by the citizens of Wallaroo for winning the Yorke Peninsula Premiership for 1913. Altogether about 100 people sat down for the diner. Various toasts were pr oposed and responded to. The catering was carried out by Mr James Heher. On 21 st March 1888 the Association of Yorke Peninsula was formed.' },
  { date: '28th FEBRUARY 1914', year: 1914, body: 'Annual Meeting of Wallaroo Football Club held on Tuesday evening where there was a larg e attendance. Mr J. F. Herbert M. P.presided. The following were elected as officers for the ensuing year. Patron – Mr C. Bray, President – Mr J. F. Herbert M. P. , Vice Presidents – a number, Secretary – Mr W. Bryden, Treasurer – Mr F. J. Kelly, Auditors – Messrs P. O’Loughlin and S. M. Watt, the election of Captain and Vice was left to the players to be decided at their first match. General Committee – Messrs C. Bray, F. Birbeck, T. Young, T. J. Kelly and W. Shea. Scorers – Messrs F. Birbeck and R. Finley, Trainers – Messrs W. Paull, G. Sandford, E. Peddar, F. Hopkins, R. Quick and S. Majer.' },
  { date: '24th JUNE 1914', year: 1914, body: 'Wallaroo defeated Rovers 7 goals 11 behinds(53 points) to 5 goals 8 behinds(38 points) in the first Minor Premiership of 1914 at Moonta last Saturday. Best players four named for W allaroo L. Clayton, C. Bowen, J. Peddar and L. Davies.' },
  { date: '2nd SEPTEMBER 1914', year: 1914, body: 'Wallaroo again Premiers , brilliant finish by the Blues. The match took place at Moonta and determined the second Minor Premiership. It took place before a large crowd. Final scores W allaroo 10 goals 8 behinds(68 points) to Kadina 6 goals 9 behinds(45 points). The premier team was ably represented by F and J. Peddar, Barnes, Walsh, L. Clayton, Sellars, Clarke, Davies, Sandford, Browne, Bowen, Whenan and Unwin.' },
  { date: '5th SEPTEMBER 1914', year: 1914, body: 'Gold Medal Football. This medal was generously dobnated by Mr S. A. Geering of this town. It was given for the best player in the final match. It was won by Mr L. Broardstock of the Kadina Club.' },
  { date: '11th NOVEMBER 1914', year: 1914, body: 'Wallaroo Footballers: An enlarged photo, the work of Mr H. W. Pell of Kadina, is on view at Messrs Chandler and Loy of Wallaroo. The photo is a group of Wallaroo Footballers(Premier team 1913) and the officers and supporters, it is intendedfor presentation to Dr C. E. C Wilson, who during his residenc e at Wallaroo was President of the club and a keen supporter.' },
  { date: '14th APRIL 1915', year: 1915, body: 'Y. P. Football adjourned meeting held at the Cornucopia Hotel Wallaroo on Monday evening 12 th April. Mr R. Thomas presided. Among the business the following players were granted to T. S. Robertson for Rovers, R. Roberts and H. B. Drew for Kadina, Cheynoweth, J. Olds and H. W. Clarke for Wallaroo. The season commences on 8th May 1915.' },
  { date: '8th SEPTEMBER 1915', year: 1915, body: '1915 Grand Final: Played at Kadina Show Grounds on Saturday afternoon, when a very strenuous game and exciting finish. The Turks earned the coveted position of Peninsula Premiers for 1915 season. They having won by two points, as usual a large crowd was in attendance. Best players for the Turks were Voyzey, Worrall, Andrews, Searle, Trembath, Curnow, Brown, Knight and Hunter. For Wallaroo Davies, Fos Clarke, Clayton, Peddar, Olds and others played well.' },
  { date: '15th MARCH 1916', year: 1916, body: 'TheAnnual Meeting to be held on Thursday night: Loyal Footballers:- The following who have enlisted are T. Thomas, H. Doyle, A. Young, D. Walsh, R. Olds, T. Buck, E. Hughes, J. Dobbin, C. Clarke, J. Hawkes, D. Elphick, R. Finley, C. Bowen, H. Cheynoweth, F. Way, W. Sandford, F. Strongman, F. Birbeck, S. Way, W. Emes, J. Bryden, L. Davies, W. Unwin, E. Prosser, L. Islam And E. Elphick. In addition two members, Sergeant D. Ballantyne and Private A. Elphick lost their lives In the service of the Empire. Private H. Brown was with the famous 10 th at the landing and Corporal Masher Thomas, after many months in the trenches is returning home incapacitated for furth er service. There is eleven of the Premiership team included in the above list. It can be said the “Wallaroos” are Doing their bit for the Empire.' },
  { date: '25th MARCH 1916', year: 1916, body: 'Wallaroo Football Club Annual Meeting: Mr F. Birbeck presided over a large attendance. Mr W. Bryden the Secretary gave his report. Mr C. Bray President complimented the club on its record it had established in providing men for active service. The Secretary Mr W. Bryden, after 17 years in office tendered his resignation, a resolution was unanimously carried that the thanks of the club be tendered to Mr Bryden for his splendid service. The resignation was not accepted and Mr Bryden will act for the current year. Election of officers: Patron – Mr C. Bray, President – Mr J. F. Herbert M. P, Secretary – Mr W. Bryden, Treasurer – Mr F. J. Kelly, Time Keeper – Mr W. Shea, General Committee – Messrs W. J. Williams, R. Thomas, T. Young and F. Clayton, Trainers – Messrs W. Paull, G. Sandford and H. McLean.' },
  { date: '2nd JULY 1916', year: 1916, body: 'Wallaroo Team to play Moonta Young Turks at Moonta today 2nd July. R. Walsh(Captain), R. Jones, T. Kiely, J. Herbert, E. Bollmeyer, J. Gepp, A. Levido, D. Hopkins, J. Evans, A. Clements, Willis(2), Brazil, S. McKee, F. Cropley, J. Hehir, A. Middleton, L. Walters and W. Phillips. Emergencies S. Phillips and D. Heath.' },
  { date: '24th MARCH 1917', year: 1917, body: 'Wallaroo Football Club: At the Annual Meeting held in the Town Hall on Monday night the 19 th, in the absence of the President Mr J. F. Herbert M. P the chair was taken by Mr F. Birbeck. It was resolved as last year that Association games are not justified until victorious termination of the WAR. Reference was made that no less than 60 members of the club had enlisted. The officers were elected.' },
  { date: '15th MAY 1918', year: 1918, body: 'Patriotic Footballers: In response to a request from the Y. M. C. A Committee, a la rge meeting of footballers met at the Wallaroo Institute on Wednesday night, for the purpose of arranging for Matches in aid of Red Cross and Y. M. C. A funds. Mr F. Birbeck was voted to the chair. It was unanimous Met with support of all present. It was resolved that a football club be formed and a series of matches played, with the object of raising funds for the patriotic societies named, a nominal fee of 1 shilling per member. The following officers were elected: President – Mr F. Birbeck, Vive president – Mr R. G. Thomas, Secretary – Mr W. Bryden, Treasurer Mr T. Young, Committee – The President, Vice President, W. Johns, L. Batten and W. J. Williams.' },
  { date: '27th JULY 1918', year: 1918, body: 'Y. P. Football Association Meeting: Meeting held at Mr Harry Richards rooms Moonta Wednesday evening last 24th. To finalise arrangements for the playing two rounds of matches. In the absence of the President Mr R. Truscott snr was voted to the chair. Delegates present Messrs R. Thomas and W. Bryden - Wallaroo, R. Bonney and M. Darmondy - Federal Rovers, R. Truscott and R. Roberts - Kadina, A. Floyd and P. London - Turks. Letters were received from W. McNiece, Secretary Australia Day – Wallaroo and A. C. Langsford Secretary Red Cross Special Appeal Kadina, asking that matches be arranged in their towns on August 3rd and September 7th respectively in the interest of the said funds. Matches were arranged accordingly, but it was decided that applications for patronage must be made to the respective clubs. Applications for the position of Central Umpires were received from Ja ck Doyle – Wallaroo, Hedley Raymond – Kadina, W. G. Hand – East Moonta, W. Westley – Wallaroo Mines and J. Whitbread – Wallaroo. All applications were accepted.' },
  { date: '3rd AUGUST 1918', year: 1918, body: 'PatrioticFootball Match: In connection with the Australia Day celebrations i n aid of the Soldiers Fund a football match was played between Point Pearce natives and Wallaroo club at the Wallaroo oval. After an exciting game in which the natives proved their superiority the match ended in favour of the natives by four points. Mr W. Whitehead officiated as central umpire. An afternoon tea booth in charge of the Ladies Committee did good business. The gate takings amounted to 15 pounds.' },
  { date: '25th SEPTEMBER 1918', year: 1918, body: 'Y. P. Association: Wallaroo wins Premiership. The final match between the Kad ina and Wallaroo clubs on Saturday September 21st for the premiership attracted a crowd reminiscent of pre war days. The competition was in aid of funds for the Kadina War Loan Committee. Final scores Wallaroo 3 goals 14 behinds(32 points) to Kadina 1 goal 1 behind(7 points).' },
  { date: '18th OCTOBER 1918', year: 1918, body: 'Wallaroo Football Club: The Annual Meeting of the Wallaroo Patriotic Football Club was held at the Institute on Friday night. There was a large attendance, the Secretary Mr W. Bryden submitted a lengthy and comprehensive report of the seasons operation. The Wallaroo club won the Y. P. Premiership. The sum of 103pounds/7 shillings/6 pence had been raised for the various patriotic funds, and apportioned as follows:- Y. M. C. A 18 pounds, Red Cross Society 17 pounds/11 shillings, Cheerup Society 6 pounds/11 shillings, Australia Day Fund 51 pound/5 shillings/6 pence. The club donated the sum of 7 pounds/18 shillings/4 pence, the individual players also contributed 2 pounds/1 shilling/8 pence.' },
  { date: '19th MARCH 1919', year: 1919, body: 'Wallaroo Football Club: The Annual Meeting of the Wallaroo Football Club was held on Thursday night last. Mr F. W. Birbeck was in the chair. Offices appointed as follows: Patron – Mr. P. Symons, President – Mr F. W. Birbeck, Vice Presidents – a number, Secretary – Mr W. Bryden, Treasurer – Mr F. J. Kelly, Auditors Mr P. O’loughlin and Mr S. Majer, Captain and Vice Captain were left over for a later appointment, Selection Committee – Captain, Vice Captain, Secretary and Messrs W. J. Williams and A. Clayton, General Committee – Messrs F. W. Birbeck, H. Brown, T. Young, A. Clarke, P. Symons, L. Batten and W. Bryden, Delegates – W. Bryden and R. G. Thomas, Time Keeper – W. Shea and F. C. Clayton, Shed Stewards – S. Majer and W. Paull, Trainers – S. Grillett, F. Hopkins, W. Paull, E. Peddar, S. Majer and G. Sandford. Goal Umpires – L. Clayton and A. Clarke.' },
  { date: '17th SEPTEMBER 1919', year: 1919, body: 'The Wallaroo Football Club concluded a successful season on Saturday, when they meritoriously won the Premiership of the 1919 season. Final scores Wallaroo 6 goals 15 behinds(51 points) to Kadina 5 goals 5 behinds(35 points). Best for Wallaroo J and F Peddar, H. Sellars, D. O’Leary, Bradley Brothers, Clarke Brothers, G. Samuels, L. C. Clayton, W. Moore and J. Evans.' },
  { date: '29th MARCH 1920', year: 1920, body: 'Wallaroo Corporation at the meeting Monday 20 th March gave approval for the Wallaroo Football Club permission to install a Bath Heater. Secretary Honored: Mr W. Bryden who held the position of secretary of the Wallaroo Football Club for a period of 20 years was on Wednesday evening last the recipient of a handsome testi monial from the club. Mr Bryden was owing to other duties been obliged to relinquish the position. The President and others spoke of his services to the club. It was decided to present him with the Olympic Cup, a silver trophy won by the club on three occasions in the premiersghip matches. Mr Bryden in acknowledging the gift, expressed his intention of still remaining an active member of the committee.' },
  { date: '29th MARCH 1920', year: 1920, body: 'Wallaroo Football Club: At the Annual Meeting held on Wednesday night last, Mr W. Chap man was appointed as Secretary with Mr F. W. Birbeck as President.' },
  { date: '14th APRIL 1920', year: 1920, body: 'Y. P. Football Association:- Season to open on May 1st. The adjourned meeting with Mr L. H. Shepley President of the Kadina Club in the chair. The following delegates were present: Messrs H. G. Banfield and P. Rogers(Turks), R. G. Thomas and W. C. Chapman(Wallaroo), A. Darmondy and J. H. Roberts(Federal Rovers), R. P. Birdsey and F. W. Harris(Kadina). The Sergeants of Police of Kadina, Moonta and Wallaroo would render every assistance in preventing spectators from encroaching on the playing arenas.' },
  { date: '7th JULY 1920', year: 1920, body: 'Wallaroo still on top:- Final scores Wallaroo 6 goals 10 behinds(46 points) v Rovers 6 goals 5 behinds(41 points) are premier of the first Premiership. Best for Wallaroo: - Bradley, Peddar(Captain), Evans, McLean, Clayton, Samuels, Clarke and Treglasi.' },
  { date: '1st SEPTEMBER 1920', year: 1920, body: 'The play off match will take place between Wallaroo and Rovers on Moonta Recreation ground next Saturday. Special trains will run from Kadina leaving at 1. 45 pm.' },
  { date: '18th SEPTEMBER 1920', year: 1920, body: 'Football Premiership:- Wallaroo secure honors, final scores Wallaroo 8 goals 13 behinds(61 points) defeated Rovers 6 goals 4 behinds(40 points). WENESDAY 15th SEPTEMBER 1920. Honoring Wallaroo Footballers:-On Tuesday night at the Parish Hall a complimentary social was tendered to the Wallaroo Football Club and supporters by Messrs Clayton Bros. In honor of the team having won the Premiership of the Y. P. Association for 1920. Cr R. G. Thomas( vice president) took t he chair over a large and enthusiastic attendance. Various toasts were proposed. The toast to Messrs Clayton Bros. Was proposed by Mr W, Bryden. The chairman said that the club had won the premiershipfor 14 seasons out of 28. Musical items were rendered and supper provided.' },
  { date: '19th MARCH 1921', year: 1921, body: 'Football:- A large and enthusiastic crowd attended the meeting of the Wallaroo Club, held Thursday night last. Mr F. W. Birbeck presided: The report presented by Mr W. J. Chapman, showed that the finances were good. Two playing members Messrs S. Treglasi and W. Moore were leaving, but a number of promising juniors are forth coming. Patron - Mr C. L. Bidstrup, President – Mr F. W. Birbeck, Secretary – Mr W. Bryden, Treasurer – Mr F. J. Kelly, Delegates – Messrs R. G. Thomas and W. Bryden, Head Trainer – Mr H. McLean, Coach – Mr W. Peckham. Regret was expressed that the Secretary Mr W. J. Champion could not continue as Secretary, and he was heartily thanked for his services. He was voted an honorarium of 5pound/5shillings.' },
  { date: '2nd APRIL 1921', year: 1921, body: 'Annual Meeting of the Yorke Peninsula Football Association was held at Wallaroo on March 23 rd. Mr S. M. Watt(local president) took the chair. The following delgates were nominated and approved: - Wallaroo – R. G. Thomas and W. Bryden, Kadina – R. J. Champion and V. Ronald, Turks – H. C. Banfield and W. Jones, Rovers – C. Brown and H. Henderson. Dr S. Holder offered a Gold Medal for competition by the players of the association and the offer was accepted. The following offiders were appointed: - Patron – Dr S. Holder, Presidents – Dr A. R. Clayton(Moonta) and Mr L. H. Shepley(Kadina) and Mr S. M. Watts (Wallaroo), Vice Presidents – Mr R. S. Richards M. P. (Moonta), Mr M. J. Reed(Kadina) and Mr F. W. Birbeck(Wallaroo), Secretary/Treasurer – Mr R. J. Hughes, Auditors – T. H. Cock and A. L. Floyd, sole arbiter Mr L. H. Shepley. The meeting decided that matches commence on Saturday April 30 th Central Umpire fees set at 35 shillings and 2 pounds a match. Boundary Umpires 10 shillings. The question of a B. Grade Association was referred to a special committee. A noti ce of motion was given to alter the rule respecting the play off matches to be played on neutral grounds instead of neutral towns.' },
  { date: '30th APRIL 1921', year: 1921, body: 'Wallaroo Football Club Teams for the opening match 1921 season:- J. Peddar, F. Bradley, J. Bradley, L. Clayton, B. McLean, W. Burgess, D. O’Leary, L. Tessiere, L. Mutton, H. Cheynoweth, C. Trembath, R. Killmier, F. Owers, R. Clarke, N. Clarke, W. Emes, J. Spry, M. Doyle. Emergency C. Dalby.' },
  { date: '22nd JUNE 1921', year: 1921, body: 'Y. P. Minor Premiership:- Won by Wallaroo in exciting game at Moonta on Saturday last beating an old rival Kadina. Final scores Wallaroo 9 goals 9 behinds(63 points) Kadina8 goals 8 behinds(56 points).' },
  { date: '30th JULY 1921', year: 1921, body: 'Social to Footballers:- A social was tendered to the members of the Wallaroo Football Club by Messrs Clayton Bros on Wednesday night in the Parish Hall. Mr F. W. Birbeck(president) took the chair , during which he reffered to the prominent position held by the Wallaroo Club in the premiership matches. He predicted that the club would retain the Fulton Shield again this year. Messrs Clayton Bros were thanked for their generous and continuous support of the club. A musical program and card games were provided. The following took part in the program:- Messrs W. Hayes, J. Davey, W. Symons, W. Phillips, J. Whisson, J. Lawson, E. Deer, Rev. T. Willason and Master H. Clayton. Mr S. Martin was accompianist.' },
  { date: '31st AUGUST 1921', year: 1921, body: 'Y. P. Football:- Kadina wins Minor Premiership over Wallaroo, in what was a stirring open game and the result was in doubt till the end. Final scores:- Kadina 8 goals 11 behinds(59 points) to Wallaroo 7 goals 9 behinds(51 points). The Central umpire M. Quigley gave one of the best exhibitions in that capacity seen here.' },
  { date: '15th MARCH 1922', year: 1922, body: 'Wallaroo Football Club:- Annual meeting held at the Druids Hall on Thursday evening. Mr Birbeck was in the chair. The Secretary Mr Bryden presented the annual report and balance sheet. Mr Bryden tendered his resignation as secretary, owing to leaving the district, his resignation was accepted with regret. The following officers were elected:-Patron – Mr C. Bidstrup, President – Mr F. Birbeck, Secretary – Mr J. Stranger, Treasurer – MrT. Kelly, Assistant Secretary – Mr Don O’Leary, Selection Committee – Messrs H. McLean, W. Peckham, Club Captain, Vice Captain and Secretary. General Committee – Messrs T. Young, F. C. Clayton, H. Davies, Don O’Leary with President, Captain, Vice Captain and Secretary. Delegates – Messrs R. G. Thomas and J. Stranger, Goal Umpires – Messrs F. C. Clayton, W. Peckham and G. Jones, Trainers – Messrs H. McLean, A. Clayton, W. Peckham, S. McLean, W. Paull, G. Sandford, F. Hopkins and T. Hopkins. Time Keeper – Mr W. Shea, Scorers – J. F. Birbeck and R. Rowe, Auditors - Messrs H. Davies and L. McLean, Coach – The Captain.' },
  { date: '28th JUNE 1922', year: 1922, body: 'Y. P. Football Association:-Kadina beat Wallaroo to be Minor Premiers. Final scores Kadina 17 goals 8 behinds(110 points) Wallaroo 7 goals 13 behinds(56 points). Mr Waters of Adelaide gave a first class exhibition as central umpire. He stated that it was one of the fastest games he had taken part in.' },
  { date: '4th SEPTEMBER 1922', year: 1922, body: 'Wallaroo win Minor Premiership of the second half defeating Kadina. With one of the biggest crowds assembled to witness the game. Final scores Wallaroo 5 goals 7 behinds(37 points) Kadina 2 goals 8 behinds(20 points). Wallaroo best players:-O’Leary, Davies, Dalby, Shuttleworth, McLean, Hopkins, Tessiere, Boyce and Burgess.' },
  { date: '13th SEPTEMBER 1922', year: 1922, body: 'Kadina Minor Premiers of the Association defeating Wallaroo. Final scores:- Kadina 7 goals 17 behinds(59 points) Wallaroo 4 goals 17 behinds(41 points).' },
  { date: '17th MARCH 1923', year: 1923, body: 'Annual Meeting held at the Druids Hall on 8th March. Mr F. W. Birbeck presided, Mr Stranger(secretary) gave his report. The Captain Mr J. Peddar was successful in winning the medal for best all round pl ayer in the Y. P. F. A. The record for the year was 93 goals 136 behinds(694 points) against 64 goals 87 behinds(471 points). J. Peddar topped the goal kicking with 16 goals , C. Trembath and F. Bradley were runners up with 14. The President and Secretary were reelected. Coach – R. Nottage. It was decided to convene a meeting with the view of forming a junior club.' },
  { date: '9th MAY 1923', year: 1923, body: 'Y. P. Association opened on Saturday last . With Kadina verses Wallaroo at the Kadina Showgrounds. Final scores Kadina 6 goals 8 behinds to Wallaroo 3 goals 2 behinds. Best for Wallaroo:- J. Peddar, L. Clayton, Shuttleworth and R. Killmer. Central Umpire Mr P. Sampson.' },
  { date: '22nd AUGUST 1923', year: 1923, body: 'Y. P. Football:- A record crowd witnessed the match between Federal Rovers and Wallaroo at Moo nta, for the Minor Premiership of the second half in conection with the association. The gate receipts totaled 241 pounds a record. Final scores Rovers 7 goals 10 behinds to Wallaroo 4 goals 14 behinds.' },
  { date: '26th MARCH 1924', year: 1924, body: 'The Wallaroo Football Club Annual meeting held in the Institute on Tuesday evening 18 th, with Mr F. W. Birbeck the Chairman in the chair. The secretary in his report stated that although they had not gained the premiership, but congratulated the players on the splendid improvement made during the season. At the end of the first half we were bottom, but during the second half we worked our way up to Second place. The Gold Medal donated by Mr H. C. Bowne won by L. Clayton for most unselfish player. Gold Medal donated by Mr J. Stranger for most improved junior player was won by G. Buck. A new departive was made during the season in having a chain of smoke socials, tendered by Messrs J. Stranger, H. B. Wall, R. Wall, Geo McKee and A. Clayton, which were highly appreciated and best thanks of the club are due to the donors. A junior club was successfully formed during the season (Wallaroo 11) and several promising juniors were admitted into our team from their ranks. The following were elected as officers for the coming season:- Patron – W. P. Symons, President – re elected, Secretary/Treasurer H. Davies, Assistant Secretary – G. Samuels, Auditors – S. McLean and S. Stranger.' },
  { date: '30th APRIL 1924', year: 1924, body: 'Y. P. Football:- Association clubs active: “Wallaroo Club” is expected to put a good combinationinto the field. There is much interest amongst the players, the majority of the older players will be available and led by the champion J. Peddar. There are a number of promising juniors and quite a few new men who have recently arrived in the town and are expected to don the Blue and White. Mr Harry Davies has taken over the duties of general secretary from Mr j. Stranger.' },
  { date: '12th JULY 1924', year: 1924, body: 'Wallaroo still on top, when they gave one of their best displays for the season at Moonta, when Wallaroo played Kadina for the Minor Premiership of the Y. P. Association. Final scores Wallaroo 8 goals 7 behinds to Kadina 6 goals 8 behinds. For Wallaroo all the team played well.' },
  { date: '17th SEPTEMBER 1924', year: 1924, body: 'Wallaroo wins the Y. P. Football Association final played at Kadina. In ideal weather, which attracted a crowd of about 3, 000 spectators. Wallaroo beat Moonta Turks. Final scores Wallaroo 7 goals 7 behinds to Turks 5 goals 11 behinds. The whole of the 36 players did exceptionally well, D. Searle (Turks) best on ground.' },
  { date: '25th MARCH 1925', year: 1925, body: 'Annual Meeting held on Monday evening 23 rd March. The president Mr F. Birbeck presided, the secretary’s report was presented which showed the past season had been a success. The club winning both minor and major premierships. They were gratified in securing Mr S. Hockinh as football coach from Adelaide, who put the team through solid training for the final and helped raise the sandard of football on the peninsula. The position of Patron, President and Secretary were all re-elected.' },
  { date: '22nd APRIL 1925', year: 1925, body: 'Y. P. Peninsula Association: At the adjourned meeting held in the Kadina Town Hall building on Monday evening 20th April it was decided that the season open on Saturday 9 th May. The following central umpires were accepted: J. R. Olds(Wallaroo), B. Wallis, P. Sampson, W. Armstrong(Moonta), A. Mashford (Kadina). Owing to the clubs financial position not being so strong, that the charge for admission to Association matches be Adults 11d(plus tax1d) 1/- , Children 5 1/2d(plus tax1/2d) 6d.' },
  { date: '1st JULY 1925', year: 1925, body: 'Wallaroo wins minor premiership played at Kadina on Saturday last. Mr Melville, S. A. League umpired the game and acquitted himself most satisfactorily. Final scores Wallaroo 10 goals 11 behinds to Turks 7 goals 8 behinds. Best players: The whole team of the winners played well. For the Turks J. Brown, Pedler, Evans, Porter, Searle, Spafford.' },
  { date: '18th JULY 1925', year: 1925, body: 'Wallaroo oval and Sunday football: At the Wallaroo Council meeting held on Monday night 12 th July the use of the oval by the football club was discussed. The following motion was carried: That the oval use by the footballers be granted from 11am to 1pm for the purpose of using the bath and dressing rooms, and that such be confined to players, trainers, and executive members of the senior club. An amendment was moved but lost.' },
  { date: '9th SEPTEMBER 1925', year: 1925, body: 'Wallaroo wins Premiership of the Y. P. Association: Played at Moonta on Saturday last 5 th September in good weather conditions. Final scores Wallaroo 10 goals 12 behinds to Kadina 9 goals 9 behinds. Best players:- Wallaroo:L. Clayton, Bradley, Brown, Boyce, Peddar, Buck, Young, Lawson and Conaughty. Kadina: Rose, Trenwith, Eddy, Brian, Trenberth and Rodda.' },
  { date: '16th SEPTEMBER 1925', year: 1925, body: 'A team of South Adelaide B. Grade players visited Wallaroo last week and spent a few days in the town. They were accorded a civic reception by the Mayor(Dr W. H. Harbison). On Saturday they played a match at Wallaroo with the senior team premiers of the Y. P. Association. An interesting and enjoyable game resulted in a win for Wallaroo 9 goals 7 behinds to South Adelaide 8 goals 7 behinds, Mr B. Wallis umpired. In the evening at Ranclauds Café a dinner was tendered the Wallaroo club in honor of their winning the Premiership, the visitors were invited besides a number of supporters, Mr F. W. Birbeck in the chair. During the evening presentations were made to Mr J. Peddar(Captain), J. Evans(Vice Captain) and Norman Clarke of a gold watch each, three of the veteran players , who have intimated their intentions of retiring from the game. The gathering was marked by the enthusiasm shown by the recipients, they each responded. Musical items were contributed by Messrs W. T. Phillips, W. H. Hayes, R. H. Wooley, T. R. Williams and W. Henderson. The South Adelaide men enjoyed the trip. The name of Mr W. O. Jones also helped with the musical items.' },
  { date: '17th APRIL 1926', year: 1926, body: 'Winner of the Holder Medal for Best and Most Gentleman player of the season was J. Hopkins of the Wallaroo club. (1925) The adjourned meeting of Y. P. Association held Tuesday April 12 th. The following central umpires were appointed:-Messrs Rosevear and J. R. Olds(Wallaroo), B. Wallis (Moonta Mines), , and W. R. Moore(Kadina).' },
  { date: '24th APRIL 1926', year: 1926, body: 'Wallaroo Annual Meeting held and some alterations were affected in the personel of the committee and officers. Mr F. W. Birbeck was re-elected President, Messrs T and A. R. Young joint Secretary/Treasurer, Vice President – H. Davies resigned. W. Paull has replaced W. Shea, the veteran Time Keeper of many years, Messrs J. Stranger and J. Woods were re-elected Association Delegates. The Committee are Messrs J. Peddar, J. Evans, R. Nottage, W. Bennett, Captain, Vice Captain and joint Secretaries. The prospects point to a good season and a strong team. It is understood that owing to the financial position the admission charge will be raised to one shilling. The Junior Association will have two teams from Wallaroo , the Swimmers and Wallaroo Clubs.' },
  { date: '5th MAY 1926', year: 1926, body: 'Wallaroo Junior Football: The Annual Meeting was held on Thursday 1 st March. The Treasurers report showed the club to be in good financial position. The President MrC. Rusk donated a Medal for competition during the season and this was won by J. Paull, the votes being decided by the umpires. The President Mr Rusk was re-elected, Vice Presidents – Messrs R. Strongman, W. Bennett and H. R. Job, Secretary - Mr L. F. Jones, Treasurer – Mr G. Boase, Committee – President, Captain, Vice Captain, J. Paull, F. Thomas, J. Doyle and Secretary, Selection Committee – Captain, Vice Captain, Secretary, J. Paull and J. Graham, Delegates to Association – K. Davies and L. F. Jones, Proxy J. Paull.' },
  { date: '23rd JUNE 1926', year: 1926, body: 'Kadina defeats Wallaroo in the first minor Premiership for 1926 at Moonta Saturday 19 th June. Final scores Kadina 10 goals 5 behinds to Wallaroo 8 goals 11 behinds.' },
  { date: '25th AUGUST 1926', year: 1926, body: 'The Holder Medal for 1926 was won by D. Lawson of Wallaroo, for the Y. P. Football Association’s Best and Fairest Player. SATUDAY 14th AUGUST 1926 Yorke Peninsula Football Association: Final held at Moonta Oval on Saturday last August 21 st. Kadina 7 goals 12 behinds to Wallaroo 7 goals 10 behinds. As Kadina had won the first minor premiership they by defeating Wallaroo is the holder of the Fulton Shield. Mr G. Quinn the senior League umpire, umpired the match, interpreted the rules with promptness and decision. He missed very little indeed and earned the commendation of players and spectators alike. The number of free marks awarded to either side (including penalties for kicking out of bounds) were Kadina 44 marks, Wallaroo 46. Best for Kadina: Gluis, Rodda, Thomas, Allen, Eddy, Kempster and Trenwith. Wallaroo: Lawson, A and C. Boyce, Edwards, Bradley, Conaughty, Buck and Young.' },
  { date: '16th MARCH 1927', year: 1927, body: 'Junior Football: After a drawn final game, another was played between Wallaroo Juniors and the Wallaroo Swimmers the final scores Juniors 5 goals 8 behinds to Swimmers 4 goals 2 behinds. After the match supporters of the Wallaroo Juniors carried the Captain J. Paull shoulder high to the dressing room. Mr H. Rosevear(Coach) and Mr S. Walsh(President) of the Swimmers congratulated the winners. Best for the winners it was hard to separate J. Paull and E. Buck. Mr J. Olds had charge of the game and very good exhibition of umpiring. WEDNESDAY ? SEPTEMBER 1926. Wallaroo Swimmers Annual Meeting held on Tuesday 8 th, when good numbers and intending members were present. Great appreciation was shown by the for the help and advice given them last season by the hon coach(Rosevear) and it was unanimously decided to ask him to accept the position for the coming season. The secretary was also asked to convey the thanks of the memb ers to Sergeant E. Eyre for the handsome trophy he presentedto the best Swimmers player in last years final match. It was resolved to present the joint secretaries F. Errington and W. Phillips and the head trainer Mr R. Kerslake with a small kit bag in recognition of services rendered. A committee was formed to obtain a small tablet for the grave of their late clubmate A. Sandford. The club sincerely thanked all who helped financially or in any way last season. The following were elected as main officers for the coming year:- Patron – Mr H. B. Wall, Vive Patrons – Srgt E. Eyre and Mr E. B. Williams, President – Mr S. Grillett, Secretary – Mr F. Errington, TreasurerMr W. Phillips, Coach – Mr H. Rosevear, Delegates – Messrs F. Errington and S. Grillett, Proxy – W. Phillips, Selection Committee – Captain, Vice Captain, R. Kerslakeand D. McLean.' },
  { date: '9th APRIL 1927', year: 1927, body: 'Wallaroo Football Club and the Oval: A deputation from the Wallaroo Football Club consisting of Messrs J. Stranger and J. Woods was introduced to the Wallaroo Corporation on Monday evening by Cr P. A. Edwards. Mr Stranger said they had been deputed to approach the Corporation in regard to the rental of the pval for the coming season. After many questions and much discussion it was resolved on the motion of Crs E. Donell and P. A. Edwards that the Wallaroo Football Club be charged 5 pound a match for the use of the oval and grandstand.' },
  { date: '30th APRIL 1927', year: 1927, body: 'Kadina and Wallaroo Junior Association: Annual Meeting which was held at the Kadina Central Hotel, when the chairman presided over a good gathering. The election of officers results: Patrons - Dr S. E. Holder and Mr F. B. Williams, President – Mr C. Ruch(Wallaroo), Mr R. P. Birdsey(Kadina), Mr W. Pearce(Tickera), Vice Presidents – Messrs A. Clayton and H. Davies(Wallaroo), Mr K. Sandercock(Kadina)Mr A. D. Bruce(Alford), Secretary/Treasurer - Mr H. W. McNeilly, Arbiter – Mr C. M. Pearson, Auditor Mr E. Cornelius, Club Delegates – Messrs S. McInerney and J. Wilton(Kadina), C. Brown and C. Milne(Rovers), F. Errington and S. Grillett(Wallaroo Swimmers), L. F. Jones a nd H. Brown(Wallaroo Juniors), R. M. Easther and M. Kelly(Alford), J. Mann and C. Heath(Tickera). Rule seven was altered to read”All play off matches to be played in a neutral town”.' },
  { date: '22nd JUNE 1927', year: 1927, body: 'Wallaroo won minor premiership played at Moonta on June 18th. Final scores Wallaroo 7 goals 13 behinds to Kadina 6 goals 9 behinds. Best for Wallaroo – Edwards, Lawson, Drew, Buck, Moyle, Smith, Young and Paull. Kadina – Mitchell, Eddy, E. C. Phillips, Trenberth, Heath, Roberts and Flint.' },
  { date: '31st AUGUST 1927', year: 1927, body: 'Wallaroo wins Premiership match at Moonta on Saturday 27 th August under excellent weather conditions. The standard of play was decidedly poor, with little good flashes. Final scores Wallaroo9 goals 7 behinds to Kadina 4 goals 15 behinds. Best players:all Wallaroo team played well, Graham, Edwards and Lawson being most conspicuous. Kadina was well served by Heath, A. Trenberth, Eddy, Byran and Davies.' },
  { date: '7th APRIL 1928', year: 1928, body: 'Wallaroo Junior Football Club meeting held on Tuesday 3rd April, when Mr L. McLean presided over a large attendance of members and players. Mr L. McLean was re-appointed as President. In the Secretaries report, that although the team was not successful in winning the premiership, we were beaten in the Semi final by Tickera after a good game. The standard of football in the junior association was very high last year. I would also like to congratulate Messrs M. Paddick, G. Moyle and J. Paull upon their promotion to senior ranks. Several conferences were held during the year with the senior football committee, the Swimmers committee, and representatives of our own club which helped to keep the three clubs in touch with one another. Our best thanks are due to Mr R. Edwards who presided over such gatherings. One cannot let pass the wonderful work done by the dance committee with Messrs Moore and Graham as joint Secretaries, also the Ladies committeeMesdames J. Doyle, Rowe and Maddison. Also the coach and head trainer.' },
  { date: '20th JUNE 1928', year: 1928, body: 'Wallaroo Minor Premiers:Stirling game at Moonta. Played at Moonta Oval on Saturday 16th June between Wallaroo and Kadina. Before a large, crowd gate receipts 104 pounds. The game was in the charge of Umpire Rohrig(Adelaide) who has many Agrade matches to his credit. Final scores Wallaroo 12 goals 13 behinds to Kadina 12 goals 9 behinds. Both teams played well, the two outstanding figures were Edwards(Wallaroo) and Gann(Kadina)who rendered yeoman service to their respective sides. Best players besides the ons mentioned were, Wallaroo – Bradley, W Lander, Payne, McLean and J. Graham. Kadina – Kessell, Champion, Richards, Bailey and Borden.' },
  { date: '12th SEPTEMBER 1928', year: 1928, body: 'Kadina wins Premiership at Moonta Oval on Saturday 8 th September. The gate takings were 150 pounds, with a large crowd present. Mr G. Rohrig of the Adelaide League, had charge of the game, he gave a good exhibition of unpiring and was prompt in his decisions. Final scores Kadina 11 goals 14 behinds to Wallaroo 9 goals 16 behinds. Goal Kickers for Kadina - Barnden 3, F. G. Phillips 2, C. Heath 2, E. Phillps, K. Bailey, McKenzie and Kessell 1 each. For Wallaroo - H. Graham 7, Campbell and Boyce 1 each. Best players Kadina – Eric Gann, C. Heath, C. Flint, K. James, R. Byran and K. Bailey. Wallaroo – H. Graham, E. Steer, P. Miller, A. Boyce, G. Moyle and W. Campbell.' },
  { date: '20th MARCH 1929', year: 1929, body: 'Y. P. Football:Annual Meeting held at Wallaroo on Tuesday evening 26 th March, when a good attendance, delegates were present. Mr T, Young being in the chair. The annual report was presenred by the Secretary(Mr H. W. McNeilly)and adopted. The result of the Holder Medal was awarded to E. Gann of Kadina. Correspondence from the ButeFootball Club, seeking affiliation with the Y. P. Association, after discussion it was decided not to entertain the application. The chairman the presented the Fulton Shield to the Kadina ClubPremiers for 1928 . Mr F. Spurling(Delegate) accepted shield on behalf of his club. Among the officers elected were: Patron – Dr S. E. Holder, Presidents – Mr R. W. Herbert(Kadina), Mr P. A. Edwards(Wallaroo), Mr R. S. Richards M. P. (Moonta), Mr J. H. Bussenchutt Jnr. (Paskeville). Vice Presidents – Mr W. J. Reed(Moonta)Mr G. T. Herbert(Kadina)Mr H. Davies(Wallaroo), Dr C. Piper(Paskeville), Secretary/Treasurer - Mr W. H. McNeilly. Mr F. W. Birbeck was made a Life Member of the Association. The season to open on 11 th May.' },
  { date: '27th APRIL 1929', year: 1929, body: 'Wallaroo Juniors Annual Meeting held on Monday evening 8 th April. Mr L. McLean was in the chair. The main officers for the 1929 season: President – Mr L. McLean, Vice Presidents – Messrs W. H. Benett, W. Hughes and H. B. Wall, Secretary/Treasurer – Mr L. F. Jones, Coach – Mr B. McLean.' },
  { date: '3rd JULY 1929', year: 1929, body: 'Y. P. Football:Wallaroo wins Minor Premiership at the Moonta Oval last Saturday. Umpire G. Rohrig of the S. A League had charge of the game sometimes he let the game get out of hand. Final scores Wallaroo 13 goals 13 behinds to Kadina 10 goals 12 behinds. No best players given although a Woodrow hat donated to the Kadina best player was won by K. Kessell.' },
  { date: '18th SEPTEMBER 1929', year: 1929, body: 'The Premiership Match: Exciting contest won by Kadina , the match was well contested with players on both sides playing top football. It was well umpired by Mr Rohrig. Final scores Kadina 12 goals 15 behinds to Wallaroo 11 goals 11 behinds. Among the best players were for Kadina – K. James(who won the Srgt A. Willington trophy), K. Bailey, A. Plumb, M. Roberts and M. McCartey, for Wallaroo E. Gann, J. Graham, E. Steer (these three stood out above their team mates), others mentioned A. Anderson, F. Errington and B. McLean.' },
  { date: '30th APRIL 1930', year: 1930, body: 'Wallaroo Club Annual Meeting: Junior Football: Held on Friday 25th April. Mr L. McLean presided as chairman. He made special reference to Mr L. F. Jones who has occupied the position of Secretary since 1923. The membership fee was fixed at 2 shillings. The following were the main officers elect ed: Patrons – Messrs F. J. Pengelly and W. Ward, President – Mr W. Bennett, Vice Presidents – Messrs W. Chapman, H. B. Wall and J. Olds, Secretary/Treasurer – Mr L. F. Jones, Selection Committee – Messrs L. F. Jones, L. P. McLean, K. Willis, P. Evans and J. Ladner.' },
  { date: '3rd SEPTEMBER 1930', year: 1930, body: 'The Annual Meeting of the Wallaroo Football Club of 1930 could not be recorded due to poor state of print. Y. P. Football Final played at Moonta on Saturday 30 th August between Kadina and Bute. Won by Kadina 15 goals 14 behinds to Bute 11 goals 22 behinds.' },
  { date: '1st OCTOBER 1930', year: 1930, body: 'Wallaroo Football Club: The proposal of the Wallaroo Football Club to build a club and dressing room on the local oval area, was before the Wallaroo Council at Monday nights meeting, consequent on the receipt of a letter from the Secretary(Mr F. J. Pengelly) to that effect, the letter stated that the clubroom would be built of stone and pug, faced with lime and sand, the dimensions would be 20ft by 40ft. After much discussion it was finally approved subject to the works committee.' },
  { date: '18th FEBRUARY 1931', year: 1931, body: 'Wallaroo Corporation Meeting held Monday 16 th February. Correspondence from Wallaroo Football Club asking for four electric light poles to carry the light to the new clubroom at the oval, also enquiring whether any old cable were available for linking up. It was moved and carried that any posts or materials required by the Football Club be given to the club for the extension of electric light.' },
  { date: '28th MARCH 1931', year: 1931, body: 'Annual Meeting Wallaroo Football Club was held in the new hall at the oval on Thursday evening the 19th. The Chairman(Mr P. A. Edwards)presided over a very large attendance, he said he was pleased to be first to preside in the new hall. The officers elected were: Patrons – Mayor Mr D. F. Warmington, Messrs H. B. Wall and W. H. Ward, President – Mr P. A. Edwards, Vice President – several, Secretary/Treasurer – Mr F. J. Pengelly, Auditors – Messrs Nottage and L. McLean. The President also spoke of the excellent services of the Head trainer Mr Jas Buck had been a hard worker for many years and the meeting thought it only right that he should be made a Life Member of the club. Mr Buck duly acknowledged the honor bestowed upon him. A minute was also taken recording the services of Mr J. Stranger, who for the past ten years had acted as Delegate and always had the Clubs welfare at heart. Mr Stranger was unable to attend due to sickness and the Secretary was asked to convey the clubs appreciation of his valuable service.' },
  { date: '29th JULY 1931', year: 1931, body: 'Kadina gain minor Premiership, ”a bumpy game”. On Saturday July 25th Wallaroo and Kadina met at Wallaroo. The weather was most unsuitable for football with a strong breeze blowing straight down the field, plus poor umpiring by Mr N. Wright. Final scores: Kadina 13 goals 11 behinds to Wallaroo 10 goals 12 behinds: Best players Kadina – McDonald, McCarthy, Gann, Roberts and Freebairn. Wallaroo – Barker(played brilliantly), Lander and Buck.' },
  { date: '19th APRIL 1933', year: 1933, body: 'Football Y. P. Association meeting held at Kadina on Monday evening. All clubs were re presented and Mr Z. Woods President of Wallaroo club presided. The following officers were elected: Patron – Dr S. E. Holder, Secretary/Treasurer Mr H. W. McNeilly, Auditors – Messrs C. Larcombe and E. Cornelius, sole Arbitor Mr J. .Stranger. Dr Holder was made a Life Member of the Association.' },
  { date: '3rd JUNE 1933', year: 1933, body: 'Wallaroo Football Club Dance: A “Blue and White Ball”, arranged by the combined Wallaroo Football Clubs was held in the Wallaroo Town Hall on Wednesday night. The ball was tastefully decorated, music supplied by the Wallaroo Syncopators. Mr J. Lander was M. C . It was in connection with the Queen contest, Miss Beryl Wall was crowned Football Queen by the Mayor Mr Harbison. The other Queen entrants were Miss L. Ward, K. Brown and M. Lander. A delicious home made supper was served during the interval in the dancing. Mr F. R. Bickley with a strong committee of ladies and gentlemen carried out the arrangements. The result a very successful social event.' },
  { date: '26th SEPTEMBER 1934', year: 1934, body: 'Y. P. Football: Wallaroo Eliminated in the Preliminary Final on Saturday 16th September at Wallaroo, umpire was Currie. Final scores Kadina 8 goals 8 behinds to Wallaroo 7 goals 5 behinds. Frees Wallaroo 10, Kadina 5. Umpire Currie gave a fairly good exhibition, marred occasionally by inconsistency. 1933. Meetings in conection with the Wallaroo Football Club, held on April 5 th and 12th when Mr Woods presided over a good attendance, players and supporters. The financial position read by the Secretary and considered very satisfactory. The following officers were elected for the coming year: Patrons – Messrs H. B. Wall, W. H. Ward, W. L. O’Connor and T. L. Liddy, President - Mr P. Edwards, Vice Presidents- several, Secretary - Mr O. Cross, Delegates – Messrs R. Humphreys and A. Hocking, Proxy – Messrs P. Edwards and O. Cross. They were the main officers. Mr B. McLean who was retiring from playing football has been made a Life Member of the Club, in recognition of his valued services. STURDAY 14th APRIL 1934. Turks defeat Wallaroo in Semi Final: At the Kadina Show Grounds on September 15th before a good crowd. Final scores Turks 13 goals 17 behinds to Wallaroo 12 goals 9 behinds. Wallaroo will meet Kadina in the Preliminary Final. Kadina too strong for Wallaroo. Fina scores Kadina 19 goals 13 behinds to Wallaroo 13 goals 16 behinds.' },
  { date: '4th SEPTEMBER 1935', year: 1935, body: 'Mail Medal was won by R. Lander of the Wallaroo Club and M. Trengove of Bute won the Holder Medal. 1934. Port Wallaroo defeats Wallaroo in the competition on Saturday last at Moonta August 31 st. Port Wallaroo played superior football to defeat Wallaroo by a margin of 62 points. The game produced some splendid football. Umpire Thomas(S. A. League) controlled the game throughout with consistent and promptness. Final scores Port Wallaroo 18 goals 16 behinds to Wallaroo 9 goals 8 behinds. Frees Wallaroo 7, Port Wallaroo 7. For the winners all played well, Wallaroo best: Buck, Jamieson, Westlake, Goodier and Chandler.' },
  { date: '18th SEPTEMBER 1935', year: 1935, body: 'East Moonta defeats Port Wallaroo: Final scores East Moonta 13 goals 13 behinds to Port Wallaroo 10 goals 7 behinds, played at Kadina Show Grounds. Best for the winners Gilbert, Woodward, Wallis and K. Pryor, for the losers Lander, Evans, Warner and Wilson.' },
  { date: '25th JULY 1936', year: 1936, body: '1935 Mail Medal to R. Lander Captain of Port Wallaroo. Y. P. Football Association: On Tuesday July 21 st at the Executive meeting passed the following motion unanimously: That this Association go into recess and that Mr T. J. Davies be appointed custodian of the Fulton Shield, that all accounts as presented by the Secretary be paid and ha be empowered to dispose of the Uniforms, Footballs and other property.' },
  { date: '8th MAY 1937', year: 1937, body: 'Y. P. Football :SUCCESSFUL REVIVAL OF ASSOCIATION. League Officials visit three towns:The S. A. National Football League: T he chairman of the league(Mr T. B. O’Halloran), the Deputy Vice chairman(Mr J. J. Woods), Secretary of the league(Mr T. S. Hill) and others addressed meetings at Kadina, Moonta and Wallaroo on May 4 th and 5th. Maitland and Curramulka Clubs were admitted to the Y. P. Football Association. At the three town meetings it was decided to reform the clubs and Association. Mention was made that (H. C. A. Harrison who lived till 91) was the founder of the Australian Game and that Mr Duncan still alive was the first field umpire. On 5thMay at Kadina a conference of delegates of the Y. P. Association decided to re -organise and place teams in the field this season. Also after further discussion it was unanimously carried that Maitland and Curramulka be admitted to the Association. Norwood and Port Adelaide to play a match at Kadina on Saturday 15th May.' },
  { date: '15th MAY 1937', year: 1937, body: 'The season for the Y. P. Association will open on May 29 th when Kadina plays Wallaroo and Curramulka plays Maitland at home, Moonta will have a bye.' },
  { date: '19th MAY 1937', year: 1937, body: 'Norwood v Port final scores : Norwood 13 goals 9 behinds to Port 13 goals 8 behinds. Wallaroo Football Club: At the meeting held on Thursday evening last, when Mr P. A. Edwards presided when various officials were appointed.' },
  { date: '11th AUGUST 1937', year: 1937, body: 'Football: The Curramulka – WallarooSemi Final played at Maitland on Saturday 7 th August before a record crowd estimated at about 1000 and over 200 cars lined around the oval. Right up to the last minute the game was anyones, with weather ideal. Final scores Curramulka 10 goals 11 behinds to Wallaroo 10 goals 7 behinds: best players for the winners F. Plumer, L. Short, R. Matheson and C. May. The losers R. Olds, S. Kempster, G. Smith and S. Westlake(best on ground).' },
  { date: '22nd SEPTEMBER 1937', year: 1937, body: 'Wallaroo v North Adelaide Ramblers, in the final game of the season at Wallaroo oval 11 th September. The visitors included in their ranks two ex Wallaroo players in “Shorty and Polly” Smith who received a great cheerio. The game was affected by a strong westerly breeze. Final score s: Wallaroo 10 goals 12 behinds to Ramblers 8 goals 4 behinds. Best for Wallaroo: Pedder, Clayton, Paull and Westlake. Ramblers: Tuckey, Herriman, A. Smith and L. Smith.' },
  { date: '30th MARCH 1937', year: 1937, body: 'Wallaroo Football Club: Annual meeting held at clubrooms on Thursday March 24th. The President Mr P. A. Edwards presided. The prospect for the coming season was considered as good, the club is fairly well off financially. The following were elected as main officers: Patron – Mr A. B. Laurenti, President – Mr P. A. Edwards, Secretary - Mr E. S. Ware, Treasurer – Mr G. D. Buck, Delegates to Association – Messrs H. McAlees and W. Paull Snr, Coach – Mr J. Lukeman, Auditors – Messrs F. Errington and G. R. Furner.' },
  { date: '7th SEPTEMBER 1938', year: 1938, body: 'Y. P. Association Mail Medal has been won by R. Lander of Wallaroo Club, finishing one vote ahead of H. (Dribbler)Hawke of Curramulka(who by the way was last years Magarey Medallist in the S. A. N. F. L. ), G. Downs of Moonta in third place. Lander had won the medal in 1934 and 1935. In 1936 he stripped for Port Adelaide in the S. A. N. F. L.and in 1937 he was runner up to G. Downs. Bob Lasako won trophy for fairest and best player in his own club and a gold medal presented for the best placed man in the side.' },
  { date: '14th SEPTEMBER 1938', year: 1938, body: 'Grand Final 1938: Contested at Kadina Show Grounds on Saturday September 8th, when a large crowd was present. Final scores Moonta 13 goals 13 behinds to Wallaroo 9 goals 6 behinds. Best players Moonta – Downs, Saunders, Brendt and Champion, for Wallaroo – Lander, Clayton, Westlake and Boyce.' },
  { date: '1st OCTOBER 1938', year: 1938, body: 'Watervale Football Club visits Wallaroo and plays the Wallaroo team: Final scores Wallaroo 16 goals 11 behinds to Watervale 9 goals 7 behinds. Best for Wallaroo – Westlake, Ware, Clayton and Chittleborough, for Watervale – Holman, Graces, Pengilly and Longmire.' },
  { date: '15th APRIL 1939', year: 1939, body: 'Wallaroo Football Club: Annual Meeting held on Monday April 3 rd at the clubrooms. The Mr P. A. Edwards took the chair. The financial statement was read by the club Secretary Mr E. S. Ware, it showed a good credit balance. Messrs W. Paull L. Hopkins, T. Simpson and E. S. Ware who had worked hard in arranging a series of helpful dances. The following were elected for the coming season: Patrons – Messrs A. B. Laurenti and G. Baker, President – Mr P. A. Edwards, Secretary – Mr E. S. Ware, Treasurer – Mr G. D. Buck, Delegates to the Association – Messrs H. McAlees and W. Paull, Selection Committee – Captain, Vice Captain, Coach, Head Trainer and B. McLean(outside selector).' },
  { date: '1st JULY 1939', year: 1939, body: 'Wallaroo Football Club social evening held on Monday night last the 27th. The usual good attendance and entertainment was enjoyed by all. During the evening a letter was read to the club from Dr C. E. C. Wilson well known in Kadina and Wallaroo District, who was President of the Wallaroo Foo tball Club in 1913. He has offered the club a enlarged photograph of the Wallaroo Team that went Premiers in the 1913. This offer has been gratefully accepted. A hot pasty and coffee supper was enjoyed by all.' },
  { date: '13th SEPTEMBER 1939', year: 1939, body: 'Port Victoria Premiers of the Y. P. Association for 1939. This match was played at Moonta, was a hard fought game and the standard of the highest order at times. Final scores Port Victoria 15 goals 12 behinds to Wallaroo 13 goals 9 behinds. Main goalkickers Pt Victoria – Collins 5, Gibson 4, Wallaroo Boyce 3. Mr W. Shea presented the trophy for best player on the Wallaroo side on Saturday which was won by S. Westlake. The umpire King gave a satisfactory exhibition.' },
  { date: '24th APRIL 1940', year: 1940, body: 'Wallaroo Football Club: Seasons Trophies Mr K. Thomas has indicated his willingness to donatea gold medal for the fairest and best player for the 1940 season. Mr Don Walsh is donating a medal for the most improved player. Mr A. Penney is also making a donation to the club. The members and officials a re most grateful to these donors and generous supporters who have made donations this year. The players are training hard for the first match against Moonta. The proceeds of this match are for the local Fighting Forces Fund.' },
  { date: '7th AUGUST 1940', year: 1940, body: 'Kadina defeats Wallaroo in the 1940 Grand Final played at Moonta. Final scores Kadina 18 goals 10 behinds to Wallaroo 16 goals 12 behinds. Best playersfor Kadina – Gerke, V. Westlake, L and R Champion Wallaroo Boyce, Lander, Chittleborough and Stagg. Umpire Melville gave a satisfactory exhibiyion, in a game full of vigor and action.' },
  { date: '17th AUGUST 1940', year: 1940, body: 'Wallaroo Football Club: Presentation to Mr G. D. Buck: Held at the clubrooms on Tuesday 13 th August. The season trophies were presented and a farewell tendered to Mr G. D. Buck the popular Treasurer and ex captain of the club of a few years ago. The President Mr P. A. Edwards after making the presentations to the various players took the opportunity of saying farewell to Mr Buck, who is leaving Wallaroo to take up a position at Arthurton. Tributes were paid to Mr Buck for his services to the club, a presentation was made to him. Following this Bob Lander received a gold medal for the fairest and best player for the season, the medal was presented by Mr K. Thomas. M. Fiedler , runner up, presented by Mr A. Rosser. M. Boyce gold medal for the seasons most improved player was presented by Mr D. Walsh, R. Jenkins, runner up presented by Mr I. Lower. An enjoyable varied program followed. A tasty supper terminated a most enjoyable social.' },
  { date: '21st AUGUST 1940', year: 1940, body: 'Mail Medal winners M. Fiedler (Wallaroo) and I. Larwood (Kadina) having received 13 points each from the umpires votes, for the fairest and best player in the Y. P. F. A for the current season, the Mail sponsors of the gift, have generously decided to award a medal to each of the successful players.' },
  { date: '5th APRIL 1941', year: 1941, body: 'Will carry on this season: At a meeting of the Wallaroo Football Club held on Monday 31 st March and chaired by the President Mr P. A. Edwards. A large attendance of members discussed whether the club would carry on due to the War Effort. It was decided to carry on with the help of the older players and juniors, it was carried unanimously. Another unanimous decision that a percentage of the seasons profits would be donated to theRed Coss and Comfort Fund. The financial statement showed that the finances were good. Officers elected: President – Mr P. A. Edwards, Patrons – Mr R. J. Walsh and Capt Baker, Secretary – Mr E. S. Ware, Treasurer – Mr G. D. Buck, Delegates – Messrs H. McAlees and W. Paull Snr.' },
  { date: '14th AUGUST 1942', year: 1942, body: 'Wallaroo Juniors win Premiership: The final played at Moonta between Wallaroo and Kadina Centrals last Saturday: The final scores Wallaroo Juniors 19 goals 20 behinds to Kadina Centrals 2 goals 2 behinds. Best players – Wallaroo D. Cogan, L. Boyce, F. Olds and K. Bishop. Kadina – E. Oliver, W. Baker, J. Oliphant and D. Cross.' },
  { date: '15th SEPTEMBER 1944', year: 1944, body: 'Football : The following team is selected to represent Wallaroo in the Match against the Norwood Association team to be played at Wallaroo oval on Saturday 16th September. J. Buck, L. Westlake, R. Lander, S. Westlake, R. Baldock, H. Buck, T. Grillett, W. Grillett, L. Rosewarne, R. Thomas, L. T. Evans, L. Cooper, A. Wearne F. Olds, E. Oliver, B. Davis, D. Bruce and V. Roach.' },
  { date: '13th APRIL 1945', year: 1945, body: 'Wallaroo played their first game of the season on Saturday last at Wallaroo, they opposed a team from the Port Wakefield Proof Range. R. Neumann was central umpire with L. Hopkins and A. McIntyre goal umpires. Final scores Vistors 8 goals 5 behinds drew with Wallaroo 8 goals 5 behinds. Best players for Visitors – Watson, Peters, Wellby and Smith. Wallaroo – Lander, J. Buck, H. Buck and Rosewarne.' },
  { date: '10th AUGUST 1945', year: 1945, body: 'The Wallaroo Football Club enjoyed a social and pasty supper supplied by Mr J. T. Ormsby, at the Waterside Workers Hall. This is the third occasion during the season on which players had been entertained. The previous donors being Messrs R. I. Wall and R. J. Walsh. In the absence of the President Mr P. A. Edwards, Mr A. G. Clarke presided as M. C. .Musical items were given by Bob Errington and M. Westlake. Mr Alex Lill an ex-state footballer gave a most interesting talk. Mr P. A. Edwards tendered a vote of thanks to Mr Ormsby and Mr Lill, also to Mr R. Bowman who provided the hall hire.' },
  { date: '5th OCTOBER 1945', year: 1945, body: 'Wallaroo wins 1945 Premiership, held at Moonta. Scores - Wallaroo 11 goals 10 behinds to Paskeville 10 goals 10 behinds. Best players – Wallaroo L and S. Westlake, Evans and Baldock. Paskeville Ron Bussenchutt, Pearce, R. Price and Reed.' },
  { date: '12th APRIL 1946', year: 1946, body: 'Wallaroo Club prepares for the opening matches, commenced training on Tuesday 9 th April. Coach Harry Hawson had a fair number at practice.' },
  { date: '4th OCTOBER 1946', year: 1946, body: 'Kadina wins football premiership played at Moonta on Saturday. Before a large crowd Kadina defeated old rivals Wallaroo, gate takings were 132 pounds. Final scores Kadina 14 goals 10 behinds(94) to Wallaroo 7 goals 9 behinds(51). Best players Kadina – L. Rogers, I. Larwood and Crosby. Wallaroo – Fiedler, Evans and Green. At halftime the President of Y. P. F. A. Mr H. Mea sday introduced the Mayor of Moont Mr A. F. Snell who presented the Cowling Medal to H. Abbott(Paskeville) for the fairest player during the season.' },
  { date: '25th MARCH 1948', year: 1948, body: 'Moonta beats Wallaroo in Y. P. Football Association, played at Kadina Showgrounds Sat urday last. A record crowd was in attendance, with gate receipts of 137 pounds. After a very dull game throughout Moonta won 11 goals 8 behinds to Wallaroo 5 goals 11 behinds. Best for Moonta – R. Wearne, G. Skipworth, M. Kemp and M. Pedler. Wallaroo – S. Westlake, R. Thomas, H. Harrison and B. Ross. Umpire L. J. Quinn was in charge. The Hon R. S. Richards Medal for the most consistent Moonta player throughout the season won by Geo Skipworth, W. Johns Medal for Moonta was won by Graham Bagshaw. 1947. Annual Meeting Wallaroo Football Club was held on Sunday last, drew a large attendance. The President Mr G. Boase presided. The clubs financial position was very sound. Mr P. A. Edwards was made a Life Member and Mr Stan Westlake congratulated on the way he had collected do nations for the club. The election of officers: Patrons – Dr Robertson, Messrs G. Green, R. Walsh, H. Hawson and R. I. Wall. President – Mr G. Boase, Vice President – Mr H. McAlees, Secretary – Mr L. Hopkins, Assistant – Mr S. Ware, Treasurer – Mr S. Jackson, Delegates – Messrs E. L. Buck and W. H. Paull, Auditor – Mr F. Errington. General Business resolved that the annual subscription be 5 shillings playing members, 1 shilling other supporters. Mr Stan Westlake was appointed to collect donations. Training to commence on 30th March, opening match 24th April.' },
  { date: '24th SEPTEMBER 1948', year: 1948, body: 'Kadina wins 1948 Football Final. Held at Moonta on Saturday in warm weather. J. Champion(Kadina)in goal kicking and C. Green(Wallaroo) in marking and kicking were both outstanding in the match. Final scores Kadina 21 goals 26 behinds to Wallaroo 15 goals 11 behinds. Best players Kadina – All played well, special mention to J. Champion, Quinn, L. Beare, J. Roberts and Lawson. Wallaroo – C. Green(best on ground), L. Evans, W. Taylor, B. Ross, J. Smith and L. Cooper. Main goalkic kers J. Champion(Kadina) 8, C. Green(Wallaroo) 7. Cowling Medal won by H. Bradtke(Kadina), Davies Medal won by W. Taylor(Wallaroo).' },
  { date: '23rd SEPTEMBER 1949', year: 1949, body: 'Preliminary Football Final: Match between Moonta and Wallaroo was won by Moonta 7 goals 16 behinds to Walllaroo 8 goals 8 behinds in an exciting game. Best players Moonta – Lock, Richards, O’Olughlin and Wearne. Wallaroo – Emes, Bowman, G. Smith and Thomas.' },
  { date: '14th OCTOBER 1949', year: 1949, body: 'Footballers at Wallaroo: Arriving at Wallaroo on Saturday morning last, the Whyalla bus with 54 visitors, which included A and B Grade footballers from South Whyalla. They visited Moonta in the afternoon and at night they were guests of the local club at a dance, and a picnic at North Beach on Sunday. The football match was played on the holiday Monday. In the morning game the Bgrade match resulted in a win for Wallaroo 6 goals 11 behinds to Sth Whyalla 6 goals 2 behinds. In the afternoon match Sth Whyalla, a fair number of victorious players played(they won their Association Grand Fi nal) drew with Wallaroo, after an interesting game final scores were Sth Whyalla 7 goals 16 behinds to Wallaroo 9 goals 4 behinds. After the match the Manager and Chairman of Sth Whyalla Mr P. Reynolds presented trophiesfor the best players in th local teams, these were won by Ern Simpson B. Grade, and Jimma Evans A. Grade. Mr G. Boase presented a small trophy to L. Bade as best player for Sth Whyalla.' },
  { date: '17th MARCH 1950', year: 1950, body: 'Wallaroo Football Club Annual Meeting held at the clubrooms on Friday last and opened with a large crowd present. The members stood for a short period of silence as a mark of respect of the late Mr W. M. Hughes, a staunch supporter for many years. The clubrooms had recently been painted throughout at a cost of over 100 pound, a further asset is an X. Ray lamp which was presented by Dr Robertson. Appreciation was expressed for work done by retiring President Mr G. L. Boase and Secretary also Mrs Hopkins and Committee. The following officers were elected for the coming year: President – Mr W. H. Paull, Vice President – Mr P. Edwards, Treasurer – Mr M. Boase, Delegates – Messrs L. Hopkins, E. Buck, Secretary – to be elected later. Life Membership was bestowed on Mr Ted Buck. (Secretary Mr R. J. Buck)' },
  { date: '29th SEPTEMBER 1950', year: 1950, body: 'Wallaroo defeat Moonta at Kadina Showgrounds on Saturday last to win the 1950 Premiership by 30 points. The final score being Wallaroo 11 goals 15 behinds to Moonta 7 goals 9 behinds. Best players Wallaroo – John Smith, L. (Jim)Evans, L. Cooper and C. Green. Moonta – P. Chapman, M. Hill, M. Braley and P. Lock. At halftime interval the “Mail” and “Cowling” Medals were presented to E. Oliver(Kadina) for the best and fairest player in A. Grade. The “Davies”Medal for best and fairest player in B. Grade was presented to A. Nankivell(Paskeville).' },
  { date: '27th SEPTEMBER 1951', year: 1951, body: 'Paskeville wins their first Premiership in Y. P. Association, by defeating Wallaroo. Final scores Paskeville 20 goals 10 behinds to Wallaroo 15 goals 11 behinds. Best players Paskeville – all played well, Wallaroo – J. Smith, J. Emes, N. Simpson and B. Miller. The umpire R. Towers handled the game well.' },
  { date: '3rd APRIL 1951', year: 1951, body: 'Wallaroo Football Club :Annual Meeting held recently with a good attendance. Officers elected: President – Mr W. H. Paull, Secretary – Mr A. P. Hockings, Vice President – Mr R. Buck, Coach – Mr Ron Drew, who is an old Wallaroo player who gave good service as a wingman and rover.' },
  { date: '25th SEPTEMBER 1952', year: 1952, body: 'Wallaroo defeats Kadina in Grand Final at Moonta Oval. The umpire was H. Taylor who kept the game under control. Final scores Wallaroo – 17 goals 16 behinds to Kadina – 12 goals 10 behinds. Best foor Wallaroo D. Watson(best on ground), J. Emes, C. Green and G. Richards. Kadina – D. Spurling, L. Champion, K. Bailey and E. Oliver.' },
  { date: '5th MARCH 1953', year: 1953, body: 'Wallaroo Annual Meeting held in Waterside Workers Hall on Friday last. President Mr W. H. Paull presided. It was decided to field both A and B Grade sides. Officers elected: Patrons – Drs D. C. Bruins and Robertson, Messrs Geo Green, A. Penney, J. Ormsby, J. Wiles and E. H. McAlees. President – Mr W. H. Paull, Vice President Mr F. Jones, Secretary – Mr Reg Buck, Assistant – Mr P. Bull, Treasurer – Mr F. Barker, Delegates – Messrs E. Buck and H. Bickley.' },
  { date: '24th SEPTEMBER 1953', year: 1953, body: 'Wallaroo wins 1953 Premiership: They won their second consecutive premiership when they trounced Kadina at Moonta Showgrounds onSaturday September 19th. The Blues won practically every position on the ground, Kadina was only a shadow of the team that played early in the season. Final score Wallaroo 14 goals 13 behinds to Kadina 6 goals 5 behinds. All Wallaroo played well w ith C. Green at center outstanding, J. Emes provided a safe avenue in attack and L. Evans at fullback. Kadina – L. Champion, R. Canute both played a great game in defence, A. Martin roved well at times. The “Mail” and “Cowling” Medals were presented to the winner J. Emes of Wallaroo.' },
  { date: '18th MARCH 1954', year: 1954, body: 'Wallaroo Club Annual Meeting held at clubrooms on Sunday 14 th March. Before a good attendance the President Mr W. H. Paull in the chair. New players Ken Green(Kadina)and Frank Crosby(Alford) were welcomed. The officers for 1954 season: President – W. H. Paull, Vice President – F. A. Jones, Treasurer – J. Barker, Delegates – E. L.and H. Buck. Training commences on Tuesday 23 rd March. Club members unanimously agreed that Mr A. G. Marcus be made a Life Member. Special mention was made of the splendid work done by the social committee last season.' },
  { date: '30th SEPTEMBER 1954', year: 1954, body: 'Wallaroo wins 1954 Premiership: Staves off a determined bid in the last quarter at Moonta last Saturday 25th. Final scores Wallaroo 11 goals 6 behinds to Paskeville 9 goals 10 b ehinds. Wallaroo has now won four premierships in the last five years. In losing Paskeville was not disgraced. Best players Wallaroo – Bruce Miller, Jimma Evans, Bill Kerslake and John Emes. For Paskeville – Russell Daniel (best on ground), Lance Price, J. Snoswell and John Rundle. ”Mail and “Cowling” Medals for most outstanding player in A Grade won by Paull Chapman Moonta. ”Crosby” Medal for runner up in A. Grade Russell Daniel Paskeville. ”Bayliss” Trophy B. Grade won by Eric Matthews Paskeville.' },
  { date: '17th MARCH 1955', year: 1955, body: 'Wallaroo Football Club Annual Meeting held on Sunday morning 13 th March. Approximately 55 players, officials and supporters attended. The following were elected for 1955: President – Mr H. R. Woodforde, Secretary – Mr E. L. Buck, Assistant Secretary – Mr L. Carter, Treasurer – Mr P. L. Paull. A siren has been provided by the club in readiness for use during the forth coming season. Mr W. H. Paull was bestowed Life Membership of the club for long service to the club.' },
  { date: '29th SEPTEMBER 1955', year: 1955, body: 'Kadina defeats Wallaroo for the 1955 Premiership at Moonta. Kadinas last win was in 1948. Kadina finish the better. Final scores Kadina 14 goals 9 behinds to Wallaroo 11 goals 4 behinds. Best players for Kadina – all played well, but G. Crosby, L. Champion, C. Champion and A. Martin at their best. Wallaroo – G. Richards, H. J. Smith, C. Green and L. Evans. The umpire was W. Henderson recognised as one of the best in the state, did a very good job.' },
  { date: '22nd MARCH 1956', year: 1956, body: 'Officers elected for 1956 season: President – Mr H. Woodforde, Vice Presidents – Messrs G. Seeley and J. Backshall, Secretary - Mr E. Buck, Assistant Secretary - Mr L. Carter, Treasurer - Mr P. Cheek, Delegates – Messrs W. Paull and R. Buck. Membership fees were set at 10 shillings and six pence, each member to receive a medallion, which is a new idea for this club. The team will have a new set of guernseys for this season. Life Membership was bestowed upon J. Buck, S. Westlake, P. Miller, W. Kersklake, L. Hopkins, J. Simpson, L. Roswewarne, W. Westlake, Mrs A. Penney and Mrs S. Smith.' },
  { date: '7th FEBRUARY 1957', year: 1957, body: '1957 Football Season Wallaroo prepares: The club is grateful to their Delegates Messrs W. H. Paull and R. J. Buck for the untiring efforts by these two officials during the recent between season meetings they attended. The oval has been improved with the mounds on both side having been extended considerably. They will be graded before the season starts to enable some 500 cars to have parking space there on. The score board has been dismantled(to make way for the mound) and will be erected in a more suitable position. New showers for the players and turfing the oval are projects for the future, that will require a lot of finance and support from the public. It is hoped that the seasiders will field stong eighteens this winter.' },
  { date: '28th FEBRUARY 1957', year: 1957, body: 'WallarooAnnual Meeting held on Friday 22nd February. Mr H. R. Woodforde occupied the chair. Election of officers: Patron – G. Green, President – H. R. Woodforde, Secretary – E. L. Buck, Treasurer – Glen Tippins, Delegates – W. Paull and R. Buck, Time Keeper - W. Bettison, Goal Umpire – R. Buck. The new set of Uniforms did not come up to expectations but will be given a newlook before the 1957 matches begin.' },
  { date: '19th DECEMBER 1957', year: 1957, body: 'Memorial to Late Members. The Wallaroo Football club will hold an open air concert at the local oval under electric light on Friday December 27th. There will be a barbecue, childrens Talent Quest and fie works display. The proceeds from this concert will form a fund to build a Memorial Committee Room to the memory of their members.' },
  { date: '13th MARCH 1958', year: 1958, body: 'Annual Meeting held Sunday 23rd February when Mr H. R. Woodforde presided over a good attendance. Mr E. L. Buck gave a very comprehensive report on the past years activities, while the Delegates report was given by Mr R. J. Buck. Election of officers: President – Mr H. R. Woodforde, Secretary – Mr E. L. Buck Assistant Secretary – Mr K. Kerslake, Senior Vice President – Capt C. R. Ridley, Junior Vice President – Mr L. T. Evans, Auditor – Mr F. J. Pengelley, Delegates – Messrs W. H. Paull and R. J. Buck, Committee – Messrs E. Simpson, R. Hall, G. Lock, T. Duncan, K. Kerslake and W. Kerslake.' },
  { date: '24th JULY 1958', year: 1958, body: 'Players Appointed Johnny Smith as Captain and Ken Green as Vice Captain. Mr Boyd is Coach for the coming season. Photo of the late Jim Buck presented to the club by his wife. Mr Buck was an ardent worker and supporter for many yeard. He was one of three instigators in getting the present club house built. The President Howard Woodforde on behalf of Mrs Buck made the presentation, while Mr Ern Simpson accepted the memento on behalf of the members. Mr Boyd Ross also announced that a football medal which was won by the late Mr Jim Gepp while playing for Wallaroo in 1863 had been handed to him by Mr Herb Samuel and it will be suitably kept in the clubrooms.' },
  { date: '5th MARCH 1958', year: 1958, body: 'Wallaroo Football Annual meeting held Sunday 1 st March. Mr H. R. Woodforde presided. Among the officers elected were: President – Mr H. R. Woodforde, Vice Presidents – Capt C. R. Ridley and Mr H. Ladner, Treasurer – Mr J. Percy. As there were no nominations for the position of Secretary the club is hoping that a younger member may fill the gap this year.' },
  { date: '2nd APRIL 1959', year: 1959, body: 'At a special meeting of the Wallaroo Foofball Club Committee Mr Maurice McCabe was appointed Coach for the 1959 season. He has had football experience with the North Adelaide Senior Colts and North Adelaide A. Grade as a playing member. He was also Captain/Coach of the Yongala Football Club and a playing member of the Whyalla and Port Pirie Association. The new Secretary is Mr J. J. Gooley(a new resident)with sporting and secretarial experience. Mr Clarry Haylock as Assistant Secretary. Mr Harry Ladner was appointed as Head Trainer.' },
  { date: '18th FEBRUARY 1960', year: 1960, body: 'Some forty keen followers of football were present at the Annual Meeting of the Wallaroo Football Club, held on Friday evening last. With the President Mr W. H. Woodforde in the c hair. The balance sheet showed the club in a good financial position. Officers elected included: President – Mr H. R. Woodforde, Vice Presidents – Messrs L. Hughes and L. Evans, Secretary - Mr C. Haylock, Assistant – Mr T. Hughes, Treasurer – Mr J. Percy, Delegates – Messrs W. Paull and R. Lander, Coach – Mr L. Evans. Membership fee set for the season at 10 shillings and six pence. Life Membership was bestowed upon Messrs J. Kneebone and L. Evans.' },
  { date: '22nd SEPTEMBER 1961', year: 1961, body: 'Ernie Simpson appointed Wallaroo Coach for 1961. Football Club Social: Tophies won during the season were presented some are; A. Grade Best and Fairest(L. Mann Trophy)won by J. Slee. Junior scoring most medal votes(C. Bowman Trophy) won by R. Sandford. Best Forward player(Club President Trophy) won by N. Phillips. Best Back player(A. Penney Trophy) won by H. Hewitt. Most Improved player(A. Wilton Trophy) won by Don Bollmeyer. B. Grade: Best and Fairest(L. Mann Trophy) won by H. White. Runner up(Eudunda Farmers Trophy) won by M. Grillett. Colts: Best and Fairest(L. Jones Trophy) won by J. Miller.' },
  { date: '8th FEBRUARY 1962', year: 1962, body: 'The Wallaroo Football Club favors admission of two new teams into the Yorke Valley League in Alford and Bute for the coming season. Applications are now being called for the position of Coach(playing or non playing)for the 1962 season. Application close on Friday16th February when the A. G. M will be held.' },
  { date: '22nd FEBRUARY 1962', year: 1962, body: 'A. G. M.held on Friday evening last with some 50 members, players and supporters in attendance. Mr H. R. Woodforde presided. Mr W. H. Paull gave the Delegates, while the Treasurers report revealed a favorable bank balance. Election of officers for 1962: Patron – Mr L. C. Hughes M. P. , President – Mr L. T. Evans, Vice Presidents – Messrs L. C. Hughes and R. J. Thomas, Assistant Secretary – Mr E. L. Buck, Treasurer – Mr W. H. Paull, Delegates – Messrs W. H. Paull and H. T. Buck. The appointment of Secretary, Coach Goal and Boundary Umpires have been left in the hands of Committee. The appointment of Coach has been extended to Friday2nd March. Mr F. J. Pengelley was made a Life Member of the Club.' },
  { date: '5th APRIL 1962', year: 1962, body: 'Mr Vince Kelly appointed as Secretary, Mr Norm Phillips appointed as Coach. League Footballers to visit Wallaroo. When few members of the West Adelaide 1961 Premiership League team will be in attendance at training on the oval. Those making the special trip are Doug Thomas(full forward), John Ryan(centreman), Ken Eustice and Bert Johnson(wingmen). They will assist the local by taking charge of training activities.' },
  { date: '14th FEBRUARY 1963', year: 1963, body: 'At a special meeting the Committee of the Wallaroo Football Club announced that David Thomas would be the playing coach for the 1963 season. He has been a regular member of the A. Grade team since 1954 and played in the Premiership side the same season. He was vice captain to present club President Les Evans in 1961.' },
  { date: '13th FEBRUARY 1964', year: 1964, body: 'A. G. M.poorly attended: The President welcomed the Rev David Purling who hopes to play for the seagulls. Coach for the season is Bill Avery. Life Memberships were bestowed upon Colin Bowman and Eric Buck. Good news for the club that David Sheppard is returning to Wallaroo from Darwin.' },
  { date: '6th AUGUST 1964', year: 1964, body: 'Disastrous Saturday for Wallaroo Football Club, which could be called “Black Saturday”, when in the A. Grade match versus Paskeville three Wallaroo players received ba d injuries, all three were admitted to Hospital. Captain-Coach Bill Avery and team mate Darryl McKee collided head on during the game. Avery received a very badly broken nose and McKee suffered a badly lacerated cheek that needed five stiches. Malcolm Davies received a bad shoulder dislocation. In the B. Grade match Wallaroo Captain Clarrie Haylock left the field with an ankle injury.' },
  { date: '25th FEBRUARY 1965', year: 1965, body: 'A. G. M. : Two applications have been received for the coaching position of the club. The matter was left in the hands of the Management Committee to interview both. Alford members on the committee are Bill Avery and Max Martin. Life Membership was bestowed on Mr Ern Simpson and Mr John McLean. Mr L. Evans was re-elected as President, Vice President - Mr Dan McIntosh, Secretary – Darryl McKee, Treasurer – Mr D. Shields.' },
  { date: '14th APRIL 1965', year: 1965, body: 'A new scoreboard has been erected at the oval.' },
  { date: '13th MAY 1965', year: 1965, body: 'New clubrooms to be erected by the Wallaroo Football Club at the Wallaroo Oval.' },
  { date: '28th OCTOBER 1965', year: 1965, body: 'Wallaroo Club held a Wind – Up Social in the Town Hall last Friday night. The President of the club Mr L. T. Evans presented trophies won during the season, just a few: P. Hughes Best and Fairest(L. F. Jones Trophy) decided on umpires votes, J. Williams best forward(Ern Simpson trophy), R. Williams best first year player(I. Hoffman trophy), W. Rivers Services Rendered(Ern Simpson trophy).' },
  { date: '4th MAY 1967', year: 1967, body: 'Wallaroo Football Club formed in 1890. The first re-union will be held in the Town Hall Saturday 10 th June.' },
  { date: '', year: 0, body: 'Present were many past and present players some coming from over 200 miles away. The evening was one of excitement, especially from the past players, some had not seen old mates for thirty years. The main contrast was the talk of the short game to todays long kicking game. Approxiamately 150 past and present players and officials, witnessed and partook of the food on the well laden tables prepared by the local football club ladies committee. The spread was magnificent. The President of the club welcomed all present. Various toasts were proposed and some replied to. There were two guest speakers, Mr George Moyle who spoke on some of his experiences whilst playing football in this district and Mr Doug Thomas who spoke on the players who would make his “best ever” side during his career as a West Adelaide player, Captain-Coach and S. A. Statemember. At the conclusion of the official programme an open house was held until approximately 11. 30pm. 15th JUNE 1967, Wallaroo Cricket Oval. - - Wed Sep, 2nd 1885. Messrs Phillips, Chatfield, and Bews waited upon the Commission of Crown Lands and asked that leave might be granted to the Wallaroo Corporation to let ten acres of the Park Lands for recreation purposes. Mr Howe was not in, but Mr Wright advised that the only way in which i t could be done was to let the land for a temporary purpose with the right of resumption at short notice. - - W/T Sat, Sep 19. 1885. P318. C. 3. 8th Sep, 1885. Wallaroo Cricket Club. Messrs, Thompson, Lambert, Richards, Farmer, Keats and Warmington were appointed a committee to wait on the Corporation in reference to a piece of ground for recreation purposes. 13th Oct 1885. Wallaroo Corporation. W/T. Wed, Oct 21. 1885. P. 358. C. 3. Cr Malcolm proposed that the Council grant a lease at 1s per year rental for 21 years on the same conditions as contained in the Commissioners letter/ Cr Bird seconded. - - W/T. Sat, June, 19. 1886. P. 206. C. 3. Full Report. Wallaroo Ratepayers Meeting. - - -“That in accordance with clause 3, of Act 234, a portion-say about ten acres of Park Lands be dedicated for the purpose of Recreation Grounds”. (In 1886 most Football games were played on the grounds near the Fuse Factory, later known as the Band Hall. ) WALLAROO CORPORATION Tenders will be received at the Town Clerks Office, up to 12 o’clock noon, on Wednesday, July 21 st, 1886, For the following work, - - vis. , Ploughing, Levelling, Harrowing, Rolling, and Clearing off all the large stones from a portion of the South Park Lands between the Goal and Cornish Street, about 6½ acres. Neither the lowest nor any tender necessarily accepted. By Order. J. Thompson. Town Clerk. Tenders will be received at the Town Clerks office, up to 12 o’clock noon, o n Wednesday, July 21, 1886, For fencing a portion of the South Park Lands between the Goal and Cornish Street, according to Specifications, which may be seen at the Town Clerks Office. The Council do not bind themselves to accept the lowest or any tender. By Order. J. Thompson. Town Clerk. Tenders for ploughing ect for oval. C. Goodfellow. - - Pounds. 7-17s-6d R. Cowan 9- 0- 0 W. Oliphant 11-0-0 T. Watts 8-10-0 E. Paul 9-19-0 W. Jones 18-18-0 W. Heayen 17-10-0 C. Goodfellows tender accepted. Tenders for Fencing oval. - - - For six feet palings. J. Sweeney. Pounds 91-9s-0d. (to be completed in three weeks. ) Accepted. E. Paul 99-18-8 F. W. Bird 97-0-0 T. H. Boyce 98-17-0 C. Coltman 100-0-0 H. Strongman 93-0-0 W. J. Pengelley 94-0-0 R. Christopher 94-0-0 For Iron Fence. J. Sweeney Pounds 156-0-0 C. Coltman 162-13-0 J. W. Pengelley 169-10-0 R. Christopher 165-0-0 Aug 21. 1886. W/T. Wallaroo Cricket Association gave 40 Pounds to be expended on the Recreation Ground. Sept 15. 1886. Cricket Club apply to build a weather board dressing room. W/T. Wed, Nov 10, 1886. P. 371. C. .Full Report. The new oval was opened on Tuesday, 9th Nov, by a cricket match between Snowtown and Wallaroo Cricket Clubs. The Snowtown team arrived on the 11. 10am train and the game started at 11. 30. The game was played on a asphalt pitch. The game was won by Wallaroo. Mon, Dec, 28th. 1886. Wallaroo Oddfellows And Foresters Annual Festival held at oval. April, 1887. Secretary of the Wallaroo Football Club asked leave to practice on oval, and asking if members of Club would be admitted free on the occasion of matches. Wed, June 8, 1887. Council to procure four bushels of rye grass and have it harrowed into the Recreation Ground. The grounds to be closed during the springing of the grass. March, 31. 1881. From Geo. J. Middleton. Hon. Sec. Wallaroo Football Club- - - Replying to yours of 15th inst. . I am instructed to thank you for granting Oval for our matches and practising, also the free admission of members, a list of whom will be supplied before season commences. Re- gate money, my committee think that it is grasping at a little too much to expect to take the whole of the proceeds of the gate, they therefore respectfully suggest that the matter should be reconsiderd, and that we be allowed one third of the proceeds and bear half the expense of men at the gate. Of course you are aware that we need not necessarily play on the Oval at all, but we have the interest of the Corporation at heart, as well as our own. Sat. April 21. 1888. The first match of season. Wallaroo- - -Moonta. (Was this the first inter club match on oval. ?) Wallaroo Team. - - -Herbert(Capt), Edwards(Vice Capt), Walsh(3), Willis(2), Hopkins(2), Evans, Harman, Phillips, Thompson, Thomas(Tots), Price, Middleton, Bowman, Cropley. Emergencies- - -Brickman, Kissel, Hughes, Hehir. Wallaroo won- - -2Goals to 0. (Wallaroo team had photo taken at half time. ) Wallaroo Council May 23, 1888. Wallaroo Football Club still after one third of gate takings. Also asking to be allowed to build a training and dressing room on the goal side of cricket room. Admission to all football matches, - - -6d for adults. 3d for juveniles. Wallaroo to receive one third of proceeds. June. 1888 Training and dressing shed has been built by Football Club. WALLAROO Cricket and Football Ground 31 July 1879 Deputation by clubs to Council. Donnell John 10 Jan 1880 Valedictory Social. (School teacher. /played cricket and football. ) Football Club 29 Sep 1930 Council granted club permission to build new club and cdressing rooms at oval. Football Club 19 March 1962 A deputation from the Wallaroo Football Cub meet council on the turfing of the oval. Football Club 10 January 1962 Club decided to change colours to red white and blue similar to Central Districts. Football Club 7 June 1919 Unveiling Football Club Honor Roll by Mr. W. Bryden at oval. Hopkins Tommy Feb 1941 Left Wallaroo after 53 years to live in Sydney with Grandson. Early football/cricket player. Kadina Football Club 25 June 1878 A meeting to form a club. (Members named. ) Kadina Football Club 17 July 1878 Grand opening game. /South west cnr Park Lands. Keating Vincent 17 June 1896 Obituary. Age 21yrs. /Died at Kadina Football Ground. (Spectator) New Football Club 19 May 1909 A meeting to form a club called The Wallaroo Welsh Rovers. Thomas John(Tots) 9 Jan 1904 Obituary. (Former Captain of the Wallaroo Football Team) Thomas Thomas(Masher) 20 Oct 1913 A presentation by Football Club of a purse of sovereigns for training team for premiership. Wallaroo Football Club 12 June 1867 Meeting to form a club. Wallaroo Football Club 17 June 1867 Meeting Globe Hotel. Wallaroo Football Club 29 June 1867 Opening Game. Wallaroo Football Club 6 July 1867 Get new and superior ball. Wallaroo Football Club 10 July 1867 Moonlight practice. Wallaroo Football Club 29 May 1868 Meeting. Wallaroo Football Club 21 June 1870 Opening Game. Wallaroo Football Club 13 July 1870 Played 2 nd moonlight match. Wallaroo Football Club 20 April 1871 Meeting Globe Inn. Wallaroo Football Club 29 April 1871 Opening Game at 4pm. Wallaroo Football Club 17 July 1874 Meeting at Ship Inn to form aa club. Wallaroo Football Club 6 Aug 1874 Opening Game. Wallaroo Football Club 9 Sep 1874 Game Moonta v Wallaroo at Wallaroo. Wallaroo Football Club 14 Oct 1874 closing game for season. Wallaroo Football Club 21 Oct 1874 The first full season. Wallaroo Football Club 26 April 1875 Meeting to appoint officers. Wallaroo Football Club 7 Nov 1875 Last game for season. Wallaroo Football Club 29 April 1876 Opening game. Wallaroo Football Club 21 June 1876 Wallaroo v Moonta. (Wallaroo team) Wallaroo Football Club 12 July 1876 Wallaroo v Moonta at Moonta. Wallaroo Football Club 28 May 1877 Opening game. (Report on game) Wallaroo Football Club 11 May 1878 Opening game. Wallaroo Football Club 29 April 1879 General Meeting. (Decided to use oval ball) Wallaroo Football Club 29 July 1885 A moonlight football match at ground near Fuse Factory. Wallaroo Football Club 23 Sep 1886 Team went to play Pt Augusta. /Went by the steamship Emu. Wallaroo Football Club 2 April 1896 Social for D. Thomas who is leaving the district. Wallaroo Football Club 1 Nov 1913 Olympic Cup handed over to club at Town Hall. /Photo in Wallaroo Museum. Walsh Phillip 24 Sep 1927 80 year old Wallaroo pioneer tells of early days. /Was the first field umpire of Y. P. Football Association. Willis Ned(Rockin) Feb 1940 Obituary. Age 72 born Wallaroo lived W. A. 44 years was in Wallaroo Rowing and Football Clubs. Wallaroo Football Club. ----The proposal of the Wallaroo Football Club to build a club and dressing room on the local oval area, was before the Wallaroo Council at Monday evenings meeting, consequent on the receipt of a letter from the secretary(Mr F. J. Pengelley)to that effect. The letter stated that the clubroom would be built of stone and pug, faced with lime and sand, and that the dimensions would be 20ft by 40ft. The matter was discussed by the Councillors, who stated that the need of a clubroom was obvious, as the present room was inadequate. The site of building was a matter that should be carefully considered, and the works committee should see to it that the proposed building was put where it could best serve its purpose. It was finally resolved, on the motion of Crs. R. H. Woolley and E. F. Wilkins, that the request of the club be granted, subject to the approval of the works committee. Wallaroo Oval ------ Grand Stand to be built. On Friday evening a public meeting was held at the Wallaroo Town Hall to consider the question of making improvements at the Ornamental Ground. A committee which had been appointed by the Town Council to submit a scheme for the carrying out of the improvements submitted its report. After the question had been fully discussed it was resolved that it was desirable that certain improvements, including the erection of a grand stand be carried out. Debentures o f 1pound, bearing interest of 4 per cent, are to be issued, and the Mayor , four councillors, representatives of the Football, Cricke and Tennis Clubs, and the Town Band were appointed a committee of management. The Mayor of Wallaroo(Mr J. F. Herbert. M. P. ), who has taken a great interest in the proposal, stated that the approximate cost of a grand stand would be 350pounds, but he considered that it would be well under this as a portion of the work would be done voluntry. Mr F. Stimson a local draughtsman, had kindly offered to supply plans and specifications free of cost, and a number of residents had also intimated their willingness to render practical assistance. The meeting was well attended and the project is being taken up most enthusiastically, and no difficulty is anticipated in raising the necessary funds. It is understood that the Football Club will vote a substancial amount, and other clubs will doubtless follow suit. It is proposedthat the money raised by debentures shall be repaid from the proceeds of concerts and oth er entertainments to be held, and these present pledged themselves to assist in carrying out the scheme. The need of a grand stand at the Oval has for many years been keenly felt.' },
];
